INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$You want to send the standard output of `ls -l /etc` to a file `out.txt` while DISCARDING any error messages. Which command does this?$rh2$, $rh2$[{"id":"a","text":"ls -l /etc > out.txt 2>/dev/null"},{"id":"b","text":"ls -l /etc 2> out.txt > /dev/null"},{"id":"c","text":"ls -l /etc | out.txt"},{"id":"d","text":"ls -l /etc &> /dev/null > out.txt"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`> out.txt` redirects stdout (fd 1) to the file; `2>/dev/null` discards stderr (fd 2). Option B swaps the two streams; `|` pipes to a command, not a file; option D sends everything to /dev/null first so out.txt stays empty.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want to send the standard output of `ls -l /etc` to a file `out.txt` while DISCARDING any error messages. Which command does this?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which `grep` command prints every line in `/var/log/messages` that does NOT contain the string "error", case-insensitively?$rh2$, $rh2$[{"id":"a","text":"grep -v -i error /var/log/messages"},{"id":"b","text":"grep -i -n error /var/log/messages"},{"id":"c","text":"grep -e error /var/log/messages"},{"id":"d","text":"grep -c error /var/log/messages"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`-v` inverts the match (lines NOT matching) and `-i` ignores case. `-n` adds line numbers, `-e` specifies a pattern, and `-c` only prints a count — none of those invert the match.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which `grep` command prints every line in `/var/log/messages` that does NOT contain the string "error", case-insensitively?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Logged in as user `student`, you copy a file to a remote host with `scp report.txt server:/tmp/`. What does this command rely on for authentication by default?$rh2$, $rh2$[{"id":"a","text":"An anonymous FTP session"},{"id":"b","text":"SSH — password or public-key authentication for user `student` on `server`"},{"id":"c","text":"Kerberos tickets only"},{"id":"d","text":"NFS share permissions"}]$rh2$::jsonb, $rh2$["b"]$rh2$::jsonb, $rh2$`scp` transfers files over SSH, so it authenticates exactly like `ssh` — using a password or a configured key pair for the (implied) user. It does not use FTP or NFS, and Kerberos is not required.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Logged in as user `student`, you copy a file to a remote host with `scp report.txt server:/tmp/`. What does this command rely on for authentication by default?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command immediately stops the `httpd` service and prevents it from starting at the next boot?$rh2$, $rh2$[{"id":"a","text":"systemctl disable httpd; systemctl stop httpd"},{"id":"b","text":"systemctl stop httpd && systemctl disable httpd"},{"id":"c","text":"systemctl mask httpd only"},{"id":"d","text":"systemctl reload httpd"}]$rh2$::jsonb, $rh2$["b"]$rh2$::jsonb, $rh2$`systemctl stop` halts the running service now; `systemctl disable` removes its boot-time enablement. Order does not change correctness, but both actions are required. `mask` is stronger (blocks even manual start) and `reload` only re-reads config.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command immediately stops the `httpd` service and prevents it from starting at the next boot?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command sets the default boot target to the multi-user (text, non-graphical) target?$rh2$, $rh2$[{"id":"a","text":"systemctl isolate multi-user.target"},{"id":"b","text":"systemctl set-default multi-user.target"},{"id":"c","text":"systemctl enable multi-user.target"},{"id":"d","text":"systemctl default multi-user"}]$rh2$::jsonb, $rh2$["b"]$rh2$::jsonb, $rh2$`systemctl set-default` updates the `default.target` symlink used at every boot. `isolate` switches the current session only (not persistent), and `enable` does not control the default target.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command sets the default boot target to the multi-user (text, non-graphical) target?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about inspecting logs with `journalctl` on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"`journalctl -u sshd` shows log entries for the sshd unit."},{"id":"b","text":"`journalctl -b` shows messages from the current boot."},{"id":"c","text":"`journalctl` data is persistent across reboots by default with no extra configuration."},{"id":"d","text":"`journalctl -p err` filters to entries of priority error and worse."}]$rh2$::jsonb, $rh2$["a","b","d"]$rh2$::jsonb, $rh2$Per-unit (`-u`), current-boot (`-b`), and priority (`-p`) filters are all valid. By default RHEL 9 stores the journal in volatile `/run/log/journal`; persistence requires `Storage=persistent` or creating `/var/log/journal`, so option C is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about inspecting logs with `journalctl` on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You added a new disk `/dev/vdb` and need a single GPT partition spanning the whole disk. Which non-interactive tool/command creates a GPT label and one partition?$rh2$, $rh2$[{"id":"a","text":"parted -s /dev/vdb mklabel gpt mkpart primary 1MiB 100%"},{"id":"b","text":"mkfs.gpt /dev/vdb"},{"id":"c","text":"fdisk --gpt /dev/vdb --all"},{"id":"d","text":"lvcreate -L 100% /dev/vdb"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`parted -s` runs scripted (non-interactive); `mklabel gpt` writes a GPT table and `mkpart` defines the partition. `mkfs.gpt` is not a command, the `fdisk` syntax shown is invalid, and `lvcreate` operates on an LVM volume group, not a raw disk.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You added a new disk `/dev/vdb` and need a single GPT partition spanning the whole disk. Which non-interactive tool/command creates a GPT label and one partition?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$A volume group `vgdata` has free extents. Which sequence extends logical volume `/dev/vgdata/lvweb` by 1 GiB AND grows its XFS file system online?$rh2$, $rh2$[{"id":"a","text":"lvextend -L +1G /dev/vgdata/lvweb && xfs_growfs /dev/vgdata/lvweb"},{"id":"b","text":"lvresize -1G /dev/vgdata/lvweb && resize2fs /dev/vgdata/lvweb"},{"id":"c","text":"vgextend +1G lvweb && xfs_repair /dev/vgdata/lvweb"},{"id":"d","text":"lvcreate -L 1G lvweb && mkfs.xfs /dev/vgdata/lvweb"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`lvextend -L +1G` adds 1 GiB to the LV, then `xfs_growfs` grows the mounted XFS file system (XFS uses `xfs_growfs`, not `resize2fs`). `vgextend` adds PVs to a VG, and `lvcreate`/`mkfs.xfs` would destroy existing data.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$A volume group `vgdata` has free extents. Which sequence extends logical volume `/dev/vgdata/lvweb` by 1 GiB AND grows its XFS file system online?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$You created a 2 GiB swap partition `/dev/vdb2`. Which two commands initialize and activate it?$rh2$, $rh2$[{"id":"a","text":"mkswap /dev/vdb2 ; swapon /dev/vdb2"},{"id":"b","text":"mkfs.swap /dev/vdb2 ; mount /dev/vdb2"},{"id":"c","text":"swapcreate /dev/vdb2 ; swapon -a"},{"id":"d","text":"mkswap /dev/vdb2 ; swapctl --enable /dev/vdb2"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`mkswap` writes a swap signature and `swapon` activates the area. `mkfs.swap` and `swapcreate`/`swapctl` are not RHEL commands, and swap is not mounted with `mount`. Add an `/etc/fstab` entry for persistence.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You created a 2 GiB swap partition `/dev/vdb2`. Which two commands initialize and activate it?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command formats `/dev/vgdata/lvbackup` with an XFS file system?$rh2$, $rh2$[{"id":"a","text":"mkfs.xfs /dev/vgdata/lvbackup"},{"id":"b","text":"mkfs -t ext4 /dev/vgdata/lvbackup"},{"id":"c","text":"xfs_admin -f /dev/vgdata/lvbackup"},{"id":"d","text":"mkxfs /dev/vgdata/lvbackup"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`mkfs.xfs` creates an XFS file system on the device. `mkfs -t ext4` makes ext4 (not XFS), `xfs_admin` changes parameters of an existing XFS, and `mkxfs` is not a command.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command formats `/dev/vgdata/lvbackup` with an XFS file system?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$To make `/dev/vgdata/lvbackup` mount automatically at `/backup` on boot, the MOST robust `/etc/fstab` identifier is:$rh2$, $rh2$[{"id":"a","text":"The kernel device name like /dev/sdb1"},{"id":"b","text":"A UUID (obtained with `blkid` or `lsblk -f`)"},{"id":"c","text":"The inode number of the mount point"},{"id":"d","text":"The PID of the mount process"}]$rh2$::jsonb, $rh2$["b"]$rh2$::jsonb, $rh2$A UUID is stable across reboots and disk re-enumeration, unlike kernel names such as /dev/sdb1 which can change. Inode numbers and PIDs are not file-system identifiers in fstab.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$To make `/dev/vgdata/lvbackup` mount automatically at `/backup` on boot, the MOST robust `/etc/fstab` identifier is:$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You want directory `/srv/data/shared` to allow read, write, and execute for user `bob` IN ADDITION to its normal permissions, without changing the owning group. Which command sets that ACL?$rh2$, $rh2$[{"id":"a","text":"setfacl -m u:bob:rwx /srv/data/shared"},{"id":"b","text":"chmod u+rwx,bob /srv/data/shared"},{"id":"c","text":"chown bob /srv/data/shared"},{"id":"d","text":"getfacl -m u:bob:rwx /srv/data/shared"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`setfacl -m u:bob:rwx` adds a named-user ACL entry granting bob rwx without altering ownership or the base group. `chmod` cannot name an arbitrary user, `chown` changes ownership, and `getfacl` only displays ACLs.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want directory `/srv/data/shared` to allow read, write, and execute for user `bob` IN ADDITION to its normal permissions, without changing the owning group. Which command sets that ACL?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which `dnf` command installs the `httpd` package and its dependencies non-interactively?$rh2$, $rh2$[{"id":"a","text":"dnf -y install httpd"},{"id":"b","text":"dnf get httpd"},{"id":"c","text":"rpm -i httpd"},{"id":"d","text":"dnf search httpd --install"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`dnf -y install httpd` resolves and installs dependencies, auto-confirming with `-y`. `dnf get` is not a subcommand, `rpm -i` does not resolve dependencies, and `dnf search` only searches metadata.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which `dnf` command installs the `httpd` package and its dependencies non-interactively?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command configures the system to keep its clock synchronized using the chrony service and enables it persistently?$rh2$, $rh2$[{"id":"a","text":"systemctl enable --now chronyd"},{"id":"b","text":"systemctl enable --now ntpd"},{"id":"c","text":"timedatectl set-ntp false"},{"id":"d","text":"chrony --sync now"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$RHEL 9 uses `chronyd` for NTP; `systemctl enable --now chronyd` both starts it and enables it at boot. `ntpd` is not the RHEL 9 default, disabling NTP is the opposite goal, and `chrony --sync` is not valid syntax.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/using-chrony-to-configure-ntp_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: chrony time sync"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command configures the system to keep its clock synchronized using the chrony service and enables it persistently?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You need to schedule a one-time job to run `/usr/local/bin/report.sh` at 23:30 today. Which tool is designed for one-off scheduled jobs?$rh2$, $rh2$[{"id":"a","text":"at 23:30 (then enter the command)"},{"id":"b","text":"crontab -e adding `30 23 * * *`"},{"id":"c","text":"systemctl start report.sh"},{"id":"d","text":"nohup /usr/local/bin/report.sh"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`at` schedules a command to run once at a specified time (requires the `atd` service). A cron entry would run repeatedly every day, `systemctl start` does not schedule, and `nohup` only detaches a process from the terminal.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You need to schedule a one-time job to run `/usr/local/bin/report.sh` at 23:30 today. Which tool is designed for one-off scheduled jobs?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$A rootless container is running with `podman run -d --name web nginx`. Which command creates a systemd user unit so it starts at user login (lingering enabled)?$rh2$, $rh2$[{"id":"a","text":"podman generate systemd --name web --files; then enable the generated user unit with `systemctl --user enable container-web`"},{"id":"b","text":"systemctl enable podman-web at the system level"},{"id":"c","text":"podman service install web"},{"id":"d","text":"crontab -e adding @reboot podman start web"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`podman generate systemd --files` produces a unit that `systemctl --user enable` manages for rootless, login-scoped startup (with `loginctl enable-linger` for boot-time). There is no `podman service install`, and a root-level service or @reboot cron is not the rootless-managed approach RHCSA expects.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/building_running_and_managing_containers/index","label":"RHEL 9 — Building, running, and managing containers"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$A rootless container is running with `podman run -d --name web nginx`. Which command creates a systemd user unit so it starts at user login (lingering enabled)?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command creates user `alice` with a home directory and her primary login shell set to `/bin/bash`?$rh2$, $rh2$[{"id":"a","text":"useradd -m -s /bin/bash alice"},{"id":"b","text":"usermod -a alice"},{"id":"c","text":"adduser alice --no-home"},{"id":"d","text":"passwd -add alice"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`useradd -m` creates the home directory and `-s /bin/bash` sets the login shell. `usermod` modifies an existing account, `--no-home` is the opposite, and `passwd` only manages passwords.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command creates user `alice` with a home directory and her primary login shell set to `/bin/bash`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You must force user `bob` to change his password at next login and expire the account if unused for 90 inactive days. Which command sets the password-expiry policy?$rh2$, $rh2$[{"id":"a","text":"chage -d 0 -I 90 bob"},{"id":"b","text":"passwd -e -n 90 bob"},{"id":"c","text":"usermod -L bob"},{"id":"d","text":"chage -E 0 bob"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`chage -d 0` forces a password change at next login (last-change date set to epoch) and `-I 90` sets the inactivity period. `usermod -L` only locks the account, and `chage -E 0` would set an absolute expiry date, not an inactivity window.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You must force user `bob` to change his password at next login and expire the account if unused for 90 inactive days. Which command sets the password-expiry policy?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which `firewall-cmd` command permanently allows the `http` service in the default zone and applies the change immediately?$rh2$, $rh2$[{"id":"a","text":"firewall-cmd --permanent --add-service=http ; firewall-cmd --reload"},{"id":"b","text":"firewall-cmd --add-service=http (only)"},{"id":"c","text":"firewall-cmd --enable http"},{"id":"d","text":"systemctl restart http"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`--permanent --add-service=http` writes the rule to the permanent configuration; `--reload` activates it in the running firewall. Without `--permanent` the rule is lost on reload, `--enable` is not a firewalld option, and `http` is not a systemd service.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/securing_networks/using-and-configuring-firewalld_securing-networks","label":"RHEL 9 — Securing networks: using and configuring firewalld"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which `firewall-cmd` command permanently allows the `http` service in the default zone and applies the change immediately?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$After moving content into `/var/www/html` with `mv`, Apache returns 403 errors. SELinux is enforcing. Which command restores the correct SELinux context on the web root?$rh2$, $rh2$[{"id":"a","text":"restorecon -Rv /var/www/html"},{"id":"b","text":"setenforce 0"},{"id":"c","text":"chmod -R 777 /var/www/html"},{"id":"d","text":"semanage login -a /var/www/html"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Files moved with `mv` keep their original SELinux context; `restorecon -Rv` resets them to the policy default (`httpd_sys_content_t`). Disabling enforcement or chmod 777 are insecure workarounds, and `semanage login` manages user-to-SELinux-user mappings, not file contexts.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$After moving content into `/var/www/html` with `mv`, Apache returns 403 errors. SELinux is enforcing. Which command restores the correct SELinux context on the web root?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 1, $rh2$TRUE_FALSE$rh2$::"QType", $rh2$Running `cd` with no arguments changes the working directory to the current user's home directory.$rh2$, $rh2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`cd` with no argument (equivalently `cd ~`) returns you to `$HOME`. The shell treats the bare `cd` as a request to go to the home directory, so the statement is true.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Running `cd` with no arguments changes the working directory to the current user's home directory.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You want to find every file under `/etc` larger than 1 MB. Which `find` command is correct?$rh2$, $rh2$[{"id":"a","text":"find /etc -type f -size +1M"},{"id":"b","text":"find /etc -size 1MB -file"},{"id":"c","text":"find /etc --larger 1M"},{"id":"d","text":"find /etc -type f -bigger +1M"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`find /etc -type f -size +1M` matches regular files whose size exceeds 1 MiB (the `+` means "greater than"). The other options use options/syntax (`-larger`, `-bigger`, `1MB -file`) that `find` does not support.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want to find every file under `/etc` larger than 1 MB. Which `find` command is correct?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL commands that display the contents of a text file to standard output.$rh2$, $rh2$[{"id":"a","text":"cat /etc/hosts"},{"id":"b","text":"less /etc/hosts"},{"id":"c","text":"head -n 5 /etc/hosts"},{"id":"d","text":"chmod /etc/hosts"}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$`cat` dumps the whole file, `less` is a pager that displays it, and `head -n 5` shows the first 5 lines. `chmod` changes permission bits and does not display file contents, so it is not a viewing tool.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL commands that display the contents of a text file to standard output.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command creates an empty file named `notes.txt` (or updates its timestamp if it already exists)?$rh2$, $rh2$[{"id":"a","text":"touch notes.txt"},{"id":"b","text":"mkdir notes.txt"},{"id":"c","text":"cat > notes.txt < /dev/null only on existing files"},{"id":"d","text":"rm -i notes.txt"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`touch notes.txt` creates the file if absent and otherwise updates its access/modification times. `mkdir` makes a directory, and `rm` deletes; the redirection option is malformed and not the standard idiom.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command creates an empty file named `notes.txt` (or updates its timestamp if it already exists)?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command counts the number of lines in `/etc/passwd`?$rh2$, $rh2$[{"id":"a","text":"wc -l /etc/passwd"},{"id":"b","text":"wc -c /etc/passwd"},{"id":"c","text":"grep -c \"\" /etc/passwd | sort"},{"id":"d","text":"cat -n /etc/passwd | wc -w"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`wc -l` prints the line count. `wc -c` counts bytes, and the other options either word-count or add unnecessary stages that do not give a clean line total.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command counts the number of lines in `/etc/passwd`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You need to recursively copy directory `/data` to `/backup/data` preserving permissions, ownership, and timestamps. Which command is best?$rh2$, $rh2$[{"id":"a","text":"cp -a /data /backup/data"},{"id":"b","text":"cp /data /backup/data"},{"id":"c","text":"mv -r /data /backup/data"},{"id":"d","text":"cp -i /data /backup/data"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`cp -a` (archive) is recursive and preserves mode, ownership, timestamps, and symlinks. Plain `cp` fails on directories without `-r`, `mv` relocates rather than copies, and `cp -i` only prompts before overwrite.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You need to recursively copy directory `/data` to `/backup/data` preserving permissions, ownership, and timestamps. Which command is best?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$Which extended regular expression with `grep -E` matches lines in a file that contain ONLY digits from start to end?$rh2$, $rh2$[{"id":"a","text":"grep -E '^[0-9]+$' file"},{"id":"b","text":"grep -E '[0-9]' file"},{"id":"c","text":"grep -E '^[0-9]*' file"},{"id":"d","text":"grep -E 'digits' file"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The anchors `^` and `$` bind the pattern to the whole line, and `[0-9]+` requires one-or-more digits with nothing else. Without anchors any line containing a digit matches; `[0-9]*` also matches empty/non-digit lines because `*` allows zero occurrences.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which extended regular expression with `grep -E` matches lines in a file that contain ONLY digits from start to end?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists all unit files and shows whether each is enabled, disabled, or static?$rh2$, $rh2$[{"id":"a","text":"systemctl list-unit-files"},{"id":"b","text":"systemctl list-units --failed"},{"id":"c","text":"systemctl status"},{"id":"d","text":"systemctl show --all"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`systemctl list-unit-files` enumerates installed unit files with their enablement state (enabled/disabled/static/masked). `list-units --failed` shows only failed runtime units, `status` shows a tree, and `show --all` dumps properties.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists all unit files and shows whether each is enabled, disabled, or static?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows only the most recent 50 lines of the journal and then keeps following new entries in real time?$rh2$, $rh2$[{"id":"a","text":"journalctl -n 50 -f"},{"id":"b","text":"journalctl --since 50"},{"id":"c","text":"journalctl -r -n 50 --stop"},{"id":"d","text":"tail -f journalctl"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`-n 50` limits to the last 50 lines and `-f` follows the journal as new entries arrive. `--since` expects a time, `-r` reverses order (and `--stop` is invalid), and `tail -f journalctl` treats a command name as a file.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows only the most recent 50 lines of the journal and then keeps following new entries in real time?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$A service failed to start. Which command shows its recent status, including the last log lines and the failed result?$rh2$, $rh2$[{"id":"a","text":"systemctl status httpd"},{"id":"b","text":"systemctl is-active httpd"},{"id":"c","text":"systemctl cat httpd"},{"id":"d","text":"systemctl daemon-reload"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`systemctl status <unit>` displays the active state, main PID, and the most recent journal lines, which is the first diagnostic step. `is-active` prints just a word, `cat` shows the unit file, and `daemon-reload` re-reads unit definitions.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$A service failed to start. Which command shows its recent status, including the last log lines and the failed result?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command immediately reboots the system?$rh2$, $rh2$[{"id":"a","text":"systemctl reboot"},{"id":"b","text":"systemctl isolate reboot.target"},{"id":"c","text":"systemctl restart system"},{"id":"d","text":"shutdown --reboot now -k"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`systemctl reboot` (equivalent to `reboot`) restarts the machine. There is no `reboot.target` to isolate, `restart system` is not a unit, and `shutdown ... -k` only sends a wall message without actually halting.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command immediately reboots the system?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command starts the `firewalld` service now AND ensures it starts at every boot in a single invocation?$rh2$, $rh2$[{"id":"a","text":"systemctl enable --now firewalld"},{"id":"b","text":"systemctl start firewalld --persistent"},{"id":"c","text":"systemctl enable firewalld --boot-now"},{"id":"d","text":"systemctl reload firewalld"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`systemctl enable --now firewalld` combines `enable` (boot persistence) and `start` (immediate activation). The `--persistent` / `--boot-now` flags do not exist, and `reload` only re-reads configuration.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command starts the `firewalld` service now AND ensures it starts at every boot in a single invocation?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about the `at` command for one-time scheduled jobs on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"The `atd` service must be running for `at` jobs to execute."},{"id":"b","text":"`atq` lists the current user's pending `at` jobs."},{"id":"c","text":"`atrm <jobnumber>` removes a pending `at` job."},{"id":"d","text":"`at` jobs automatically repeat every day."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$The `atd` daemon runs queued jobs, `atq` lists them, and `atrm` deletes one by job number. `at` is for ONE-TIME execution — recurring jobs are the domain of cron — so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about the `at` command for one-time scheduled jobs on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$You want a normal user `student` to run `/usr/local/bin/cleanup.sh` every day at 02:15. Which crontab entry (in `crontab -e` as that user) is correct?$rh2$, $rh2$[{"id":"a","text":"15 2 * * * /usr/local/bin/cleanup.sh"},{"id":"b","text":"2 15 * * * /usr/local/bin/cleanup.sh"},{"id":"c","text":"* * 15 2 * /usr/local/bin/cleanup.sh"},{"id":"d","text":"@daily 02:15 /usr/local/bin/cleanup.sh"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The cron fields are minute hour day-of-month month day-of-week, so 02:15 daily is `15 2 * * *`. Option B reverses minute/hour, option C misplaces the values, and `@daily` does not accept a time argument.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want a normal user `student` to run `/usr/local/bin/cleanup.sh` every day at 02:15. Which crontab entry (in `crontab -e` as that user) is correct?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command displays the amount of used and free space on all mounted file systems in human-readable units?$rh2$, $rh2$[{"id":"a","text":"df -h"},{"id":"b","text":"du -h"},{"id":"c","text":"lsblk -m"},{"id":"d","text":"free -h"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`df -h` reports per-file-system disk usage in human-readable sizes. `du -h` measures directory sizes, `lsblk -m` shows device permissions, and `free -h` reports memory, not disk.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command displays the amount of used and free space on all mounted file systems in human-readable units?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$After creating a new partition with `parted`, the kernel still does not see it. Which command forces the kernel to re-read the partition table without rebooting?$rh2$, $rh2$[{"id":"a","text":"partprobe /dev/vdb"},{"id":"b","text":"udevadm reload"},{"id":"c","text":"systemctl restart disk"},{"id":"d","text":"blkid --rescan"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`partprobe <device>` asks the kernel to re-read the partition table so new partitions appear (`partx`/`kpartx` are alternatives). `udevadm reload`, a non-existent `disk` service, and `blkid --rescan` do not perform this.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$After creating a new partition with `parted`, the kernel still does not see it. Which command forces the kernel to re-read the partition table without rebooting?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows the size, free space, and number of physical volumes in volume group `vgdata`?$rh2$, $rh2$[{"id":"a","text":"vgdisplay vgdata"},{"id":"b","text":"pvcreate vgdata"},{"id":"c","text":"lvscan vgdata"},{"id":"d","text":"vgchange -a n vgdata"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`vgdisplay vgdata` prints VG attributes including total/free PE and PV count (`vgs` gives a terse view). `pvcreate` initializes a PV, `lvscan` lists LVs, and `vgchange -a n` deactivates the VG.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows the size, free space, and number of physical volumes in volume group `vgdata`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You must reduce logical volume `/dev/vg01/lvtmp` that holds an EXT4 file system. What is the correct safe order?$rh2$, $rh2$[{"id":"a","text":"Unmount, run `e2fsck -f`, shrink the filesystem with `resize2fs`, then `lvreduce` to the same size"},{"id":"b","text":"`lvreduce` first, then `resize2fs` to grow it back"},{"id":"c","text":"`xfs_growfs` then `lvreduce`"},{"id":"d","text":"Just run `lvreduce -L -1G` while mounted"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$For ext4 you must shrink the FILE SYSTEM before the LV: unmount, force-check with `e2fsck -f`, `resize2fs` smaller, then `lvreduce`. Reducing the LV first destroys data, `xfs_growfs` is for XFS (which cannot shrink), and shrinking while mounted is unsafe.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You must reduce logical volume `/dev/vg01/lvtmp` that holds an EXT4 file system. What is the correct safe order?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows currently active swap areas and their sizes?$rh2$, $rh2$[{"id":"a","text":"swapon --show"},{"id":"b","text":"swapctl -l"},{"id":"c","text":"free --swap-only"},{"id":"d","text":"cat /etc/swap"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`swapon --show` (or `cat /proc/swaps`) lists active swap devices/files and their sizes. `swapctl` is not a RHEL command, `free` has no `--swap-only`, and `/etc/swap` does not exist (swap is declared in `/etc/fstab`).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows currently active swap areas and their sizes?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 4, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about LVM logical volumes on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"A logical volume can be extended online while mounted if the file system supports online grow."},{"id":"b","text":"Physical volumes must be created before they can be added to a volume group."},{"id":"c","text":"A volume group can contain physical volumes from multiple disks."},{"id":"d","text":"Reducing an XFS file system in place is fully supported."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$LVs can grow online (with `xfs_growfs`/`resize2fs`), PVs must be `pvcreate`d before `vgextend`, and a VG can span multiple disks' PVs. XFS does NOT support shrinking, so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about LVM logical volumes on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists existing Stratis pools and their total/used size?$rh2$, $rh2$[{"id":"a","text":"stratis pool list"},{"id":"b","text":"stratis show pools"},{"id":"c","text":"lsblk --stratis"},{"id":"d","text":"stratisctl pools"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`stratis pool list` displays each pool with its size and usage. `stratis show pools`, `lsblk --stratis`, and `stratisctl` are not valid Stratis command forms.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists existing Stratis pools and their total/used size?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command creates an ext4 file system on the partition `/dev/vdb1`?$rh2$, $rh2$[{"id":"a","text":"mkfs.ext4 /dev/vdb1"},{"id":"b","text":"mke4fs /dev/vdb1"},{"id":"c","text":"mkfs --ext4 only"},{"id":"d","text":"tune2fs -ext4 /dev/vdb1"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`mkfs.ext4 /dev/vdb1` formats the partition as ext4 (equivalently `mkfs -t ext4`). `mke4fs` is not a command, the `mkfs --ext4 only` form is incomplete, and `tune2fs` adjusts an existing ext file system.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command creates an ext4 file system on the partition `/dev/vdb1`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You added an `/etc/fstab` line and want to verify it parses correctly WITHOUT actually rebooting. Besides `mount -a`, which command validates that systemd can generate mount units from fstab?$rh2$, $rh2$[{"id":"a","text":"systemctl daemon-reload"},{"id":"b","text":"systemctl restart fstab"},{"id":"c","text":"mount --fake --all-verbose only"},{"id":"d","text":"fsck -A"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$After editing `/etc/fstab`, `systemctl daemon-reload` regenerates the systemd mount units so the new entry is recognized; combined with `mount -a` it confirms validity. There is no `fstab` service, and `fsck -A` checks file systems rather than fstab syntax.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You added an `/etc/fstab` line and want to verify it parses correctly WITHOUT actually rebooting. Besides `mount -a`, which command validates that systemd can generate mount units from fstab?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command labels an XFS file system on `/dev/vdb1` with the label `DATA`?$rh2$, $rh2$[{"id":"a","text":"xfs_admin -L DATA /dev/vdb1"},{"id":"b","text":"e2label /dev/vdb1 DATA"},{"id":"c","text":"mkfs.xfs -L DATA /dev/vdb1 (on an existing populated FS)"},{"id":"d","text":"tune2fs -L DATA /dev/vdb1"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`xfs_admin -L DATA` sets the label on an existing XFS file system. `e2label`/`tune2fs -L` work on ext2/3/4, and re-running `mkfs.xfs` on a populated file system would destroy its data.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command labels an XFS file system on `/dev/vdb1` with the label `DATA`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command displays the UUID of every block device so you can reference it in `/etc/fstab`?$rh2$, $rh2$[{"id":"a","text":"blkid"},{"id":"b","text":"lsof -u"},{"id":"c","text":"uuidgen --all"},{"id":"d","text":"cat /proc/uuid"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`blkid` lists devices with their UUID, LABEL, and TYPE (`lsblk -f` is an alternative). `lsof` lists open files, `uuidgen` generates a NEW random UUID, and `/proc/uuid` does not exist.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command displays the UUID of every block device so you can reference it in `/etc/fstab`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows the ACLs currently set on the directory `/srv/share`?$rh2$, $rh2$[{"id":"a","text":"getfacl /srv/share"},{"id":"b","text":"setfacl -x /srv/share"},{"id":"c","text":"ls -Z /srv/share"},{"id":"d","text":"lsattr /srv/share"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`getfacl` prints the access and default ACL entries. `setfacl -x` REMOVES an ACL entry, `ls -Z` shows SELinux contexts, and `lsattr` shows ext file attributes (immutable, etc.), not ACLs.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows the ACLs currently set on the directory `/srv/share`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$An NFS client needs `/exports/home` from `nfssrv` mounted at `/home` automatically at boot. Which `/etc/fstab` line is correct?$rh2$, $rh2$[{"id":"a","text":"nfssrv:/exports/home  /home  nfs  defaults,_netdev  0 0"},{"id":"b","text":"/exports/home  nfssrv:/home  nfs  defaults  0 0"},{"id":"c","text":"nfssrv:/exports/home  /home  xfs  auto  0 0"},{"id":"d","text":"nfssrv  /home  nfs4  loop  0 0"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The fstab format is `server:/export  mountpoint  nfs  options  0 0`; `_netdev` defers the mount until networking is up. Option B swaps source/target, C uses the wrong fs type, and D omits the export path and misuses `loop`.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/mounting-nfs-shares_managing-file-systems","label":"RHEL 9 — Deploying and using NFS / autofs"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$An NFS client needs `/exports/home` from `nfssrv` mounted at `/home` automatically at boot. Which `/etc/fstab` line is correct?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$You need users to access `nfssrv:/data` on demand under `/misc/data` using autofs. Which configuration is correct?$rh2$, $rh2$[{"id":"a","text":"In /etc/auto.master add `/misc /etc/auto.misc`, and in /etc/auto.misc add `data -rw nfssrv:/data`"},{"id":"b","text":"Add only an `/etc/fstab` line for /misc/data"},{"id":"c","text":"In /etc/auto.master add `nfssrv:/data /misc/data`"},{"id":"d","text":"Run `automount /misc/data nfssrv:/data` which persists by itself"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$autofs uses a master map pointing a mount point base (`/misc`) at a map file (`/etc/auto.misc`), whose entries (`data -rw nfssrv:/data`) define on-demand mounts. The other options confuse autofs with fstab or use invalid syntax.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/mounting-nfs-shares_managing-file-systems","label":"RHEL 9 — Deploying and using NFS / autofs"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You need users to access `nfssrv:/data` on demand under `/misc/data` using autofs. Which configuration is correct?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command removes the `telnet` package and any now-unneeded dependencies?$rh2$, $rh2$[{"id":"a","text":"dnf remove telnet"},{"id":"b","text":"dnf erase --keep-deps telnet"},{"id":"c","text":"rpm -e --force telnet"},{"id":"d","text":"dnf clean telnet"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`dnf remove telnet` uninstalls the package and removes leaf dependencies it pulled in. `dnf erase --keep-deps` is not standard syntax, `rpm -e --force` skips dependency handling, and `dnf clean` only clears cached metadata.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command removes the `telnet` package and any now-unneeded dependencies?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows the current time, time zone, and whether NTP synchronization is active?$rh2$, $rh2$[{"id":"a","text":"timedatectl"},{"id":"b","text":"date --ntp"},{"id":"c","text":"chronyc time"},{"id":"d","text":"hwclock --show-zone"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`timedatectl` (with no arguments) reports local/universal time, the time zone, and NTP-synchronized status. `date --ntp`, `chronyc time`, and `hwclock --show-zone` are not valid forms for that summary.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/using-chrony-to-configure-ntp_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: chrony time sync"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows the current time, time zone, and whether NTP synchronization is active?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which `nmcli` command brings the connection profile `ens3` down and back up to apply changed settings?$rh2$, $rh2$[{"id":"a","text":"nmcli con down ens3 ; nmcli con up ens3"},{"id":"b","text":"nmcli reload ens3"},{"id":"c","text":"nmcli dev restart ens3"},{"id":"d","text":"systemctl restart ens3"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Re-activating a profile with `nmcli con down` then `nmcli con up` applies modified `ipv4.*` settings. `nmcli reload` reloads NetworkManager config files, `nmcli dev restart` is invalid, and `ens3` is not a systemd unit.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_networking/index","label":"RHEL 9 — Configuring and managing networking"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which `nmcli` command brings the connection profile `ens3` down and back up to apply changed settings?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You need to install package group "Development Tools" on RHEL 9. Which command is correct?$rh2$, $rh2$[{"id":"a","text":"dnf group install \"Development Tools\""},{"id":"b","text":"dnf install group=Development-Tools"},{"id":"c","text":"dnf -g Development Tools"},{"id":"d","text":"yum addgroup \"Development Tools\""}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`dnf group install "Development Tools"` (or `dnf groupinstall`) installs all packages in the group. The other forms use option syntax that DNF does not accept.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You need to install package group "Development Tools" on RHEL 9. Which command is correct?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command displays the list of available kernel boot entries with their indices so you can pick a default?$rh2$, $rh2$[{"id":"a","text":"grubby --info=ALL"},{"id":"b","text":"grub2-list --all"},{"id":"c","text":"grubby --show-menu"},{"id":"d","text":"cat /boot/grub2/menu.lst"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`grubby --info=ALL` prints every boot entry (kernel, args, index). `grub2-list`/`--show-menu` are not commands, and RHEL 9 uses `grub.cfg`/BLS snippets, not the legacy `menu.lst`.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_monitoring_and_updating_the_kernel/index","label":"RHEL 9 — Managing the boot process / rescue & emergency targets"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command displays the list of available kernel boot entries with their indices so you can pick a default?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$Which command sets the default kernel for the next boots to the entry with index 1?$rh2$, $rh2$[{"id":"a","text":"grubby --set-default-index=1"},{"id":"b","text":"grub2-set-default --index 1"},{"id":"c","text":"grubby --default 1 --once"},{"id":"d","text":"systemctl set-default kernel-1"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`grubby --set-default-index=1` makes that BLS entry the persistent default. `grub2-set-default` takes a menu entry title/number differently, `--once` (via `grub2-reboot`) is one-time only, and `systemctl set-default` controls targets not kernels.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_monitoring_and_updating_the_kernel/index","label":"RHEL 9 — Managing the boot process / rescue & emergency targets"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command sets the default kernel for the next boots to the entry with index 1?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$A rootless container should expose its service on host port 8080. Which `podman run` option publishes container port 80 to host 8080?$rh2$, $rh2$[{"id":"a","text":"podman run -d -p 8080:80 nginx"},{"id":"b","text":"podman run -d --expose 8080 nginx"},{"id":"c","text":"podman run -d --net host 80:8080 nginx"},{"id":"d","text":"podman run -d -P 8080 nginx"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`-p 8080:80` maps host port 8080 to container port 80. `--expose` only documents a port without publishing, the `--net host 80:8080` form is invalid, and `-P` publishes all exposed ports to random host ports (no fixed 8080).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/building_running_and_managing_containers/index","label":"RHEL 9 — Building, running, and managing containers"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$A rootless container should expose its service on host port 8080. Which `podman run` option publishes container port 80 to host 8080?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about managing rootless containers with Podman on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"Rootless containers run under the invoking user's UID without root privileges."},{"id":"b","text":"`podman generate systemd` can produce unit files to manage container lifecycle."},{"id":"c","text":"A user systemd service for a container is enabled with `systemctl --user enable`."},{"id":"d","text":"Rootless containers require the Docker daemon to be running."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$Podman is daemonless and supports rootless mode; `podman generate systemd` plus `systemctl --user enable` integrates containers with the user's systemd. Podman does NOT need a Docker daemon, so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/building_running_and_managing_containers/index","label":"RHEL 9 — Building, running, and managing containers"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about managing rootless containers with Podman on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command checks the chrony tracking status to confirm the system clock is synchronized to a time source?$rh2$, $rh2$[{"id":"a","text":"chronyc tracking"},{"id":"b","text":"chronyc sources --sync"},{"id":"c","text":"systemctl tracking chronyd"},{"id":"d","text":"timedatectl ntp-status"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`chronyc tracking` reports the reference ID, stratum, offset, and whether the clock is synchronized. `chronyc sources` lists sources (no `--sync`), and the systemd/timedatectl forms shown are not valid.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/using-chrony-to-configure-ntp_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: chrony time sync"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command checks the chrony tracking status to confirm the system clock is synchronized to a time source?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command creates a new group named `engineers`?$rh2$, $rh2$[{"id":"a","text":"groupadd engineers"},{"id":"b","text":"useradd -g engineers"},{"id":"c","text":"newgrp engineers"},{"id":"d","text":"usermod -G engineers"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`groupadd engineers` creates the group in `/etc/group`. `useradd -g` sets a new user's primary group (and needs the group to exist), `newgrp` switches your active group, and `usermod -G` modifies an existing user.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command creates a new group named `engineers`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command changes the primary group of existing user `frank` to `staff`?$rh2$, $rh2$[{"id":"a","text":"usermod -g staff frank"},{"id":"b","text":"usermod -aG staff frank"},{"id":"c","text":"groupmod -g frank staff"},{"id":"d","text":"gpasswd staff frank"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`usermod -g staff frank` sets `staff` as the PRIMARY group. `-aG` adds a SUPPLEMENTARY group, `groupmod` modifies a group definition, and `gpasswd` administers group membership/passwords.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command changes the primary group of existing user `frank` to `staff`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command deletes user `guest` AND removes their home directory and mail spool?$rh2$, $rh2$[{"id":"a","text":"userdel -r guest"},{"id":"b","text":"userdel guest"},{"id":"c","text":"usermod -d /dev/null guest"},{"id":"d","text":"rm -rf /home/guest only"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`userdel -r guest` removes the account plus its home directory and mail spool. Plain `userdel` leaves the home behind, `usermod -d` only changes the home path, and `rm -rf` alone leaves the account in `/etc/passwd`.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command deletes user `guest` AND removes their home directory and mail spool?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$You must create a system account `appsvc` with no login shell and no home directory, to own a daemon process. Which command is correct?$rh2$, $rh2$[{"id":"a","text":"useradd -r -s /sbin/nologin -M appsvc"},{"id":"b","text":"useradd -m -s /bin/bash appsvc"},{"id":"c","text":"adduser --system --shell /bin/bash appsvc"},{"id":"d","text":"useradd -r -d /home/appsvc appsvc"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`useradd -r` creates a system account (low UID, no aging), `-s /sbin/nologin` blocks interactive login, and `-M` skips home-directory creation. The other options grant a shell and/or a home directory, which is wrong for a service account.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You must create a system account `appsvc` with no login shell and no home directory, to own a daemon process. Which command is correct?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists all currently allowed services in the default firewalld zone?$rh2$, $rh2$[{"id":"a","text":"firewall-cmd --list-services"},{"id":"b","text":"firewall-cmd --get-zones"},{"id":"c","text":"firewall-cmd --reload"},{"id":"d","text":"firewall-cmd --check-config"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`firewall-cmd --list-services` (or `--list-all`) shows the services permitted in the active zone. `--get-zones` lists available zones, `--reload` re-applies permanent config, and `--check-config` validates configuration.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/securing_networks/using-and-configuring-firewalld_securing-networks","label":"RHEL 9 — Securing networks: using and configuring firewalld"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists all currently allowed services in the default firewalld zone?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command sets the SELinux mode to permissive immediately (until next boot) for troubleshooting?$rh2$, $rh2$[{"id":"a","text":"setenforce 0"},{"id":"b","text":"setenforce 1"},{"id":"c","text":"getenforce permissive"},{"id":"d","text":"semanage permissive -a"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`setenforce 0` switches the running system to permissive (logs denials without blocking). `setenforce 1` returns to enforcing, `getenforce` only reports, and `semanage permissive -a` makes a specific DOMAIN permissive, not the whole system.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command sets the SELinux mode to permissive immediately (until next boot) for troubleshooting?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 2, $rh2$TRUE_FALSE$rh2$::"QType", $rh2$The command `ls -Z` displays the SELinux security context of files.$rh2$, $rh2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`ls -Z` adds the SELinux context (user:role:type:level) to the listing, while `ls -l` shows only the traditional DAC owner/group/mode. The statement is therefore true.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$The command `ls -Z` displays the SELinux security context of files.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about firewalld on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"Changes made without `--permanent` are lost after `firewall-cmd --reload`."},{"id":"b","text":"A zone defines a trust level with its own allowed services and ports."},{"id":"c","text":"`firewall-cmd --runtime-to-permanent` saves the running config to permanent."},{"id":"d","text":"firewalld and the raw `iptables` service can both be enabled simultaneously without conflict."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$Runtime-only changes vanish on reload, zones are trust levels with their own rule sets, and `--runtime-to-permanent` persists current rules. Running firewalld alongside the legacy iptables service causes conflicts, so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/securing_networks/using-and-configuring-firewalld_securing-networks","label":"RHEL 9 — Securing networks: using and configuring firewalld"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p1$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about firewalld on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command archives the directory `/home/student` into a single gzip-compressed file `backup.tar.gz`?$rh2$, $rh2$[{"id":"a","text":"tar -czf backup.tar.gz /home/student"},{"id":"b","text":"tar -xzf backup.tar.gz /home/student"},{"id":"c","text":"gzip -r /home/student backup.tar.gz"},{"id":"d","text":"tar -tf backup.tar.gz /home/student"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`-c` creates an archive, `-z` pipes it through gzip, and `-f` names the output file. `-x` extracts, `-t` only lists contents, and `gzip -r` compresses files in place rather than building a tar archive.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command archives the directory `/home/student` into a single gzip-compressed file `backup.tar.gz`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which `sed` command replaces every occurrence of `dev` with `prod` on all lines of `app.conf` and writes the change back to the file?$rh2$, $rh2$[{"id":"a","text":"sed -i 's/dev/prod/g' app.conf"},{"id":"b","text":"sed 's/dev/prod/' app.conf"},{"id":"c","text":"sed -n 's/dev/prod/g' app.conf"},{"id":"d","text":"sed -e 'dev=prod' app.conf"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`-i` edits the file in place, `s/dev/prod/g` substitutes globally on each line. Without `-i` the change only prints to stdout, without `g` only the first match per line changes, and `-n` suppresses output.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which `sed` command replaces every occurrence of `dev` with `prod` on all lines of `app.conf` and writes the change back to the file?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$You do not remember the options of the `find` command. Which command opens its manual page?$rh2$, $rh2$[{"id":"a","text":"man find"},{"id":"b","text":"find --man"},{"id":"c","text":"help find"},{"id":"d","text":"info --man find"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`man find` displays the manual page. `find --man` is not a valid option, `help` is a bash builtin for shell builtins only, and `info --man` is not valid syntax (use `info find` for the info reader).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You do not remember the options of the `find` command. Which command opens its manual page?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$A runaway process with PID 4821 must be terminated. Which command sends the default termination signal to it?$rh2$, $rh2$[{"id":"a","text":"kill 4821"},{"id":"b","text":"kill -9 -4821"},{"id":"c","text":"renice 4821"},{"id":"d","text":"nice 4821"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`kill 4821` sends SIGTERM (signal 15), the default, allowing graceful shutdown. `kill -9 -4821` targets a process GROUP with SIGKILL, while `renice`/`nice` change scheduling priority, not termination.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$A runaway process with PID 4821 must be terminated. Which command sends the default termination signal to it?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You want to lower the scheduling priority of an ALREADY RUNNING process (PID 3300) so it competes less for CPU. Which command does this?$rh2$, $rh2$[{"id":"a","text":"renice +10 3300"},{"id":"b","text":"nice -n 10 3300"},{"id":"c","text":"kill -STOP 3300"},{"id":"d","text":"chrt -f 10 3300"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`renice` changes the niceness of an existing process; a higher (more positive) nice value lowers priority. `nice` only launches NEW commands with a niceness, `kill -STOP` suspends the process, and `chrt` sets real-time scheduling policy.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want to lower the scheduling priority of an ALREADY RUNNING process (PID 3300) so it competes less for CPU. Which command does this?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command applies the `throughput-performance` tuned profile and makes it the active profile?$rh2$, $rh2$[{"id":"a","text":"tuned-adm profile throughput-performance"},{"id":"b","text":"tuned-adm list throughput-performance"},{"id":"c","text":"systemctl set-default throughput-performance"},{"id":"d","text":"tuned --profile throughput-performance --once"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`tuned-adm profile <name>` activates the named profile via the tuned daemon. `tuned-adm list` only enumerates profiles, `systemctl set-default` controls boot targets, and `tuned --profile` is not the supported management command (use `tuned-adm`).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/monitoring_and_managing_system_status_and_performance/index","label":"RHEL 9 — Monitoring and managing system status & performance (tuned)"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command applies the `throughput-performance` tuned profile and makes it the active profile?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which sequence builds an LVM stack: turn `/dev/vdb1` into a physical volume, create volume group `vg01`, then a 5 GiB logical volume `lv01`?$rh2$, $rh2$[{"id":"a","text":"pvcreate /dev/vdb1 ; vgcreate vg01 /dev/vdb1 ; lvcreate -L 5G -n lv01 vg01"},{"id":"b","text":"vgcreate /dev/vdb1 ; pvcreate vg01 ; lvcreate vg01 5G"},{"id":"c","text":"lvcreate /dev/vdb1 ; vgextend vg01 ; pvscan lv01"},{"id":"d","text":"mkfs.lvm /dev/vdb1 ; vgcreate vg01 ; lvcreate lv01"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The correct LVM order is `pvcreate` (initialize the PV) → `vgcreate` (group PVs) → `lvcreate -L 5G -n lv01 vg01` (carve out the LV). The other options reverse the order or use non-existent commands like `mkfs.lvm`.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which sequence builds an LVM stack: turn `/dev/vdb1` into a physical volume, create volume group `vg01`, then a 5 GiB logical volume `lv01`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which Stratis commands create a pool `pool1` from `/dev/vdc` and then a file system `fs1` on it?$rh2$, $rh2$[{"id":"a","text":"stratis pool create pool1 /dev/vdc ; stratis filesystem create pool1 fs1"},{"id":"b","text":"stratis create pool /dev/vdc pool1 ; stratis fs new pool1"},{"id":"c","text":"mkfs.stratis /dev/vdc ; stratis mount fs1"},{"id":"d","text":"lvcreate --stratis pool1 /dev/vdc"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Stratis uses `stratis pool create <pool> <dev>` then `stratis filesystem create <pool> <fs>`. The `stratis-cli` syntax in the other options is invalid, and Stratis is not created via `mkfs.stratis` or `lvcreate`.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which Stratis commands create a pool `pool1` from `/dev/vdc` and then a file system `fs1` on it?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$You need to add new disk `/dev/vdd` to an EXISTING volume group `vgapp` to gain more free extents. Which command does this?$rh2$, $rh2$[{"id":"a","text":"pvcreate /dev/vdd ; vgextend vgapp /dev/vdd"},{"id":"b","text":"vgcreate vgapp /dev/vdd"},{"id":"c","text":"lvextend vgapp /dev/vdd"},{"id":"d","text":"pvmove /dev/vdd vgapp"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$First initialize the disk with `pvcreate`, then `vgextend vgapp /dev/vdd` adds the new PV to the existing VG. `vgcreate` would make a new VG, `lvextend` grows an LV, and `pvmove` relocates extents between PVs.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You need to add new disk `/dev/vdd` to an EXISTING volume group `vgapp` to gain more free extents. Which command does this?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$An `/etc/fstab` line for an NFS export should use which file-system type field and a recommended mount option for resilience?$rh2$, $rh2$[{"id":"a","text":"Type `nfs` with the `_netdev` option so the mount waits for networking"},{"id":"b","text":"Type `xfs` with the `noauto` option"},{"id":"c","text":"Type `swap` with the `defaults` option"},{"id":"d","text":"Type `cifs` with the `loop` option"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$NFS mounts use fs type `nfs`; the `_netdev` option ensures the mount is attempted only after the network is up. `xfs`/`swap` are local types, and `cifs`/`loop` apply to SMB shares and loopback images respectively.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/mounting-nfs-shares_managing-file-systems","label":"RHEL 9 — Deploying and using NFS / autofs"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$An `/etc/fstab` line for an NFS export should use which file-system type field and a recommended mount option for resilience?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You want `/etc/fstab` entries that should NOT block boot if the device is missing, but still be mountable later. Which mount option fits?$rh2$, $rh2$[{"id":"a","text":"nofail"},{"id":"b","text":"remount"},{"id":"c","text":"sync"},{"id":"d","text":"ro"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The `nofail` option lets the system boot even if the device is absent, while the entry remains valid for a later `mount -a`. `remount` re-applies options, `sync` forces synchronous I/O, and `ro` mounts read-only — none address boot-blocking.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want `/etc/fstab` entries that should NOT block boot if the device is missing, but still be mountable later. Which mount option fits?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 4, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about autofs on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"autofs mounts file systems on demand and unmounts them after a period of inactivity."},{"id":"b","text":"A master map (e.g. `/etc/auto.master`) references one or more map files."},{"id":"c","text":"autofs requires editing `/etc/fstab` for every mount it manages."},{"id":"d","text":"autofs is commonly used to automount NFS home directories."}]$rh2$::jsonb, $rh2$["a","b","d"]$rh2$::jsonb, $rh2$autofs is an on-demand automounter driven by master/indirect maps, often used for NFS home directories. It deliberately replaces static `/etc/fstab` entries, so option C is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/mounting-nfs-shares_managing-file-systems","label":"RHEL 9 — Deploying and using NFS / autofs"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about autofs on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which `nmcli` command sets a static IPv4 address 192.168.10.5/24 with gateway 192.168.10.1 on connection `ens3`?$rh2$, $rh2$[{"id":"a","text":"nmcli con mod ens3 ipv4.addresses 192.168.10.5/24 ipv4.gateway 192.168.10.1 ipv4.method manual"},{"id":"b","text":"nmcli dev ip ens3 192.168.10.5"},{"id":"c","text":"ifconfig ens3 192.168.10.5 netmask 255.255.255.0"},{"id":"d","text":"nmcli con add static ens3 192.168.10.5"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Modifying the connection profile with `ipv4.addresses`, `ipv4.gateway`, and `ipv4.method manual` makes the static config persistent (re-apply with `nmcli con up ens3`). `ifconfig` is deprecated and not persistent; the other nmcli forms are invalid syntax.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_networking/index","label":"RHEL 9 — Configuring and managing networking"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which `nmcli` command sets a static IPv4 address 192.168.10.5/24 with gateway 192.168.10.1 on connection `ens3`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command sets the system static hostname to `server1.example.com` persistently?$rh2$, $rh2$[{"id":"a","text":"hostnamectl set-hostname server1.example.com"},{"id":"b","text":"hostname server1.example.com"},{"id":"c","text":"echo server1 > /proc/hostname"},{"id":"d","text":"nmcli hostname server1.example.com"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`hostnamectl set-hostname` writes `/etc/hostname` and applies it persistently. The `hostname` command only changes it until reboot, `/proc/hostname` is not writable that way, and `nmcli hostname ...` is not valid syntax.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_networking/index","label":"RHEL 9 — Configuring and managing networking"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command sets the system static hostname to `server1.example.com` persistently?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You must list all available module streams for `nodejs` and then install the `18` stream. Which commands accomplish this on RHEL 9?$rh2$, $rh2$[{"id":"a","text":"dnf module list nodejs ; dnf module install nodejs:18"},{"id":"b","text":"dnf list nodejs ; dnf install nodejs-18"},{"id":"c","text":"dnf stream nodejs 18"},{"id":"d","text":"dnf module enable 18"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`dnf module list nodejs` shows streams; `dnf module install nodejs:18` enables stream 18 and installs its default profile. Plain `dnf install nodejs-18` ignores modular metadata, and the other forms are not valid module syntax.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You must list all available module streams for `nodejs` and then install the `18` stream. Which commands accomplish this on RHEL 9?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$You must add `console=ttyS0` to the default kernel command line persistently for future boots. Which RHEL 9 tool is intended for this?$rh2$, $rh2$[{"id":"a","text":"grubby --update-kernel=ALL --args=\"console=ttyS0\""},{"id":"b","text":"grub-install --args console=ttyS0"},{"id":"c","text":"edit /proc/cmdline directly"},{"id":"d","text":"sysctl -w kernel.cmdline=console=ttyS0"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`grubby --update-kernel=ALL --args=...` edits the boot loader entries persistently. `grub-install` reinstalls the bootloader, `/proc/cmdline` is read-only, and `sysctl` tunes runtime kernel parameters, not the boot command line.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_monitoring_and_updating_the_kernel/index","label":"RHEL 9 — Managing the boot process / rescue & emergency targets"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You must add `console=ttyS0` to the default kernel command line persistently for future boots. Which RHEL 9 tool is intended for this?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command adds existing user `carol` to the supplementary group `developers` WITHOUT removing her other supplementary groups?$rh2$, $rh2$[{"id":"a","text":"usermod -aG developers carol"},{"id":"b","text":"usermod -G developers carol"},{"id":"c","text":"groupadd carol developers"},{"id":"d","text":"gpasswd -d carol developers"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`usermod -aG` APPENDS the group, preserving existing memberships. `usermod -G` (without `-a`) REPLACES the supplementary group list, `groupadd` creates a group, and `gpasswd -d` removes a member.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command adds existing user `carol` to the supplementary group `developers` WITHOUT removing her other supplementary groups?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You want members of group `wheel` to run any command via `sudo`. On RHEL 9 the recommended way to express this is to:$rh2$, $rh2$[{"id":"a","text":"Create a file under /etc/sudoers.d/ (validated with visudo) granting `%wheel ALL=(ALL) ALL`"},{"id":"b","text":"Add each user to /etc/passwd with UID 0"},{"id":"c","text":"chmod 4755 /bin/bash"},{"id":"d","text":"Edit /etc/group and set the wheel GID to 0"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$A drop-in under `/etc/sudoers.d/` with `%wheel ALL=(ALL) ALL`, edited via `visudo`, is the supported sudo configuration. Sharing UID 0, setuid-ing bash, or remapping the wheel GID are dangerous and incorrect.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want members of group `wheel` to run any command via `sudo`. On RHEL 9 the recommended way to express this is to:$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lets the Apache `httpd` process make outbound network connections by toggling the appropriate SELinux boolean persistently?$rh2$, $rh2$[{"id":"a","text":"setsebool -P httpd_can_network_connect on"},{"id":"b","text":"setenforce 1"},{"id":"c","text":"semanage fcontext -a httpd_can_network_connect"},{"id":"d","text":"restorecon -R /etc/httpd"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`setsebool -P httpd_can_network_connect on` flips the boolean and `-P` makes it persistent across reboots. `setenforce` only changes enforcing/permissive mode, `semanage fcontext` manages file contexts, and `restorecon` relabels files.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lets the Apache `httpd` process make outbound network connections by toggling the appropriate SELinux boolean persistently?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which `firewall-cmd` command permanently opens custom TCP port 8080 in the `public` zone?$rh2$, $rh2$[{"id":"a","text":"firewall-cmd --permanent --zone=public --add-port=8080/tcp ; firewall-cmd --reload"},{"id":"b","text":"firewall-cmd --add-port 8080 --temporary"},{"id":"c","text":"iptables -A INPUT -p tcp 8080"},{"id":"d","text":"firewall-cmd --open 8080/tcp"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Adding the port with `--permanent --zone=public --add-port=8080/tcp` then `--reload` makes the rule survive reloads/reboots. The `--temporary`/`--open` forms are invalid, and a raw `iptables` rule is not the firewalld-managed approach RHCSA expects.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/securing_networks/using-and-configuring-firewalld_securing-networks","label":"RHEL 9 — Securing networks: using and configuring firewalld"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which `firewall-cmd` command permanently opens custom TCP port 8080 in the `public` zone?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 1, $rh2$TRUE_FALSE$rh2$::"QType", $rh2$The `pwd` command prints the absolute path of the current working directory.$rh2$, $rh2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`pwd` (print working directory) outputs the full absolute path of the directory you are currently in, so the statement is true.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$The `pwd` command prints the absolute path of the current working directory.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command searches the file `data.txt` for lines that start with the word `total`?$rh2$, $rh2$[{"id":"a","text":"grep '^total' data.txt"},{"id":"b","text":"grep 'total$' data.txt"},{"id":"c","text":"grep -v 'total' data.txt"},{"id":"d","text":"grep 'total' --start data.txt"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The `^` anchor ties the pattern to the BEGINNING of the line, so `^total` matches lines starting with "total". `total$` anchors to the END, `-v` inverts the match, and `--start` is not a grep option.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command searches the file `data.txt` for lines that start with the word `total`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command extracts and prints just the first colon-separated field (the username) from every line of `/etc/passwd`?$rh2$, $rh2$[{"id":"a","text":"cut -d: -f1 /etc/passwd"},{"id":"b","text":"cut -f1 /etc/passwd"},{"id":"c","text":"awk '{print $2}' /etc/passwd"},{"id":"d","text":"sed -n '1p' /etc/passwd"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`cut -d: -f1` sets the delimiter to `:` and prints field 1 (the username). Without `-d:` cut defaults to TAB, the awk default delimiter is whitespace (so `$2` is wrong here), and `sed -n 1p` prints only line 1.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command extracts and prints just the first colon-separated field (the username) from every line of `/etc/passwd`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists files in the current directory sorted by modification time, newest first?$rh2$, $rh2$[{"id":"a","text":"ls -lt"},{"id":"b","text":"ls -lS"},{"id":"c","text":"ls -lr"},{"id":"d","text":"ls --sort=name"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`ls -lt` sorts by modification time with the most recent first. `-lS` sorts by size, `-lr` reverses the default name order, and `--sort=name` sorts alphabetically.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists files in the current directory sorted by modification time, newest first?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about the `tar` command on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"`tar -tf archive.tar` lists the contents without extracting."},{"id":"b","text":"`tar -xJf archive.tar.xz` extracts an xz-compressed archive."},{"id":"c","text":"`tar -czf a.tgz dir/` creates a gzip-compressed archive of dir/."},{"id":"d","text":"`tar -rf` can only be used on compressed archives."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$`-tf` lists, `-xJf` extracts xz archives, and `-czf` creates a gzip archive. `tar -rf` appends files but ONLY to uncompressed archives (you cannot append to a gzip/xz stream), so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about the `tar` command on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You connect to a remote server as `admin` on host `db1` over SSH using port 2222. Which command is correct?$rh2$, $rh2$[{"id":"a","text":"ssh -p 2222 admin@db1"},{"id":"b","text":"ssh admin@db1 -port 2222"},{"id":"c","text":"ssh --port=2222 db1 admin"},{"id":"d","text":"ssh admin:2222@db1"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The SSH port is specified with the lowercase `-p` option: `ssh -p 2222 admin@db1`. `-port`/`--port` are not valid (uppercase `-P` is for scp/sftp), and `admin:2222@db1` is not valid SSH target syntax.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You connect to a remote server as `admin` on host `db1` over SSH using port 2222. Which command is correct?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$Which command appends the standard output of `dmesg` to the file `boot.log` WITHOUT overwriting existing content?$rh2$, $rh2$[{"id":"a","text":"dmesg >> boot.log"},{"id":"b","text":"dmesg > boot.log"},{"id":"c","text":"dmesg | boot.log"},{"id":"d","text":"dmesg 2> boot.log"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`>>` appends stdout to the file, preserving prior content. `>` truncates and overwrites, `|` pipes to a command (not a file), and `2>` would redirect stderr (and also truncate).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command appends the standard output of `dmesg` to the file `boot.log` WITHOUT overwriting existing content?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows a one-time snapshot of all running processes with full details?$rh2$, $rh2$[{"id":"a","text":"ps aux"},{"id":"b","text":"top -1"},{"id":"c","text":"jobs -l"},{"id":"d","text":"pgrep -a"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`ps aux` (or `ps -ef`) prints a full one-time process listing. `top` is interactive/continuous, `jobs` lists only shell job-control jobs, and `pgrep` matches processes by name/pattern rather than listing all.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows a one-time snapshot of all running processes with full details?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You want to terminate every process named `myapp` by name. Which command does this?$rh2$, $rh2$[{"id":"a","text":"pkill myapp"},{"id":"b","text":"kill myapp"},{"id":"c","text":"killall -l myapp"},{"id":"d","text":"pgrep -k myapp"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`pkill myapp` sends SIGTERM to all processes matching the name (`killall myapp` is equivalent). `kill` needs a PID not a name, `killall -l` only lists signal names, and `pgrep -k` is not valid (`pgrep` has no kill flag).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want to terminate every process named `myapp` by name. Which command does this?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command launches `/usr/bin/backup` with a lower scheduling priority (nice value 15)?$rh2$, $rh2$[{"id":"a","text":"nice -n 15 /usr/bin/backup"},{"id":"b","text":"renice -n 15 /usr/bin/backup"},{"id":"c","text":"nice 15 -p /usr/bin/backup"},{"id":"d","text":"chrt 15 /usr/bin/backup"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`nice -n 15 <command>` STARTS a new process with niceness 15 (lower priority). `renice` only adjusts an EXISTING process by PID/user, the `nice 15 -p` form is wrong, and `chrt` sets real-time policy.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command launches `/usr/bin/backup` with a lower scheduling priority (nice value 15)?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists currently loaded systemd units that are in a failed state?$rh2$, $rh2$[{"id":"a","text":"systemctl --failed"},{"id":"b","text":"systemctl list-unit-files --all"},{"id":"c","text":"systemctl status --failed-only"},{"id":"d","text":"journalctl --failed"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`systemctl --failed` (alias of `systemctl list-units --failed`) shows units that failed to start. `list-unit-files` shows enablement state, and the `status --failed-only`/`journalctl --failed` forms are not valid.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists currently loaded systemd units that are in a failed state?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$After editing a unit file in `/etc/systemd/system/`, which command must you run before restarting the service so systemd picks up the change?$rh2$, $rh2$[{"id":"a","text":"systemctl daemon-reload"},{"id":"b","text":"systemctl reload-or-restart all"},{"id":"c","text":"systemctl reset-failed"},{"id":"d","text":"systemctl revert"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`systemctl daemon-reload` reloads the systemd manager configuration so edited unit files take effect. `reset-failed` clears failed state, `revert` discards customizations, and `reload-or-restart all` is not a valid command.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$After editing a unit file in `/etc/systemd/system/`, which command must you run before restarting the service so systemd picks up the change?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows kernel and boot messages from the PREVIOUS boot (if persistent journaling is enabled)?$rh2$, $rh2$[{"id":"a","text":"journalctl -b -1"},{"id":"b","text":"journalctl --previous"},{"id":"c","text":"dmesg -1"},{"id":"d","text":"journalctl -b 0"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`journalctl -b -1` selects the previous boot (`-b 0` or `-b` is the current boot). `--previous` is not an option, and `dmesg -1` is not valid syntax for prior-boot kernel messages.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows kernel and boot messages from the PREVIOUS boot (if persistent journaling is enabled)?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$You need a one-time job that runs in 5 minutes. Which `at` invocation schedules it correctly?$rh2$, $rh2$[{"id":"a","text":"echo \"/usr/local/bin/job.sh\" | at now + 5 minutes"},{"id":"b","text":"at --delay 5 /usr/local/bin/job.sh"},{"id":"c","text":"at +5m /usr/local/bin/job.sh"},{"id":"d","text":"sleep 300 && at job.sh"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Piping a command into `at now + 5 minutes` schedules a one-time job five minutes from now. `at` reads the command from stdin (or a file with `-f`); the `--delay`/`+5m`/`sleep` forms are not valid `at` syntax.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You need a one-time job that runs in 5 minutes. Which `at` invocation schedules it correctly?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists all physical volumes known to LVM with their volume group and size?$rh2$, $rh2$[{"id":"a","text":"pvs"},{"id":"b","text":"pvcreate --list"},{"id":"c","text":"lvs --physical"},{"id":"d","text":"vgscan --pv"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`pvs` gives a concise table of physical volumes (PV, VG, size, free). `pvcreate` initializes a PV (no `--list`), `lvs` lists logical volumes, and `vgscan` scans for VGs (no `--pv`).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists all physical volumes known to LVM with their volume group and size?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You want to set the partition type of `/dev/vdb1` to "Linux LVM" so LVM can use it. Using `fdisk`, which type code applies?$rh2$, $rh2$[{"id":"a","text":"Type code `8e` (Linux LVM) in an MBR/DOS table"},{"id":"b","text":"Type code `82` (Linux swap)"},{"id":"c","text":"Type code `83` (Linux filesystem) is required for LVM"},{"id":"d","text":"LVM cannot use partitioned disks at all"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$In an MBR/DOS partition table the "Linux LVM" type is hex `8e` (GPT uses a different GUID, set via `parted set N lvm on`). `82` is swap and `83` is a generic Linux filesystem; LVM works fine on partitions.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want to set the partition type of `/dev/vdb1` to "Linux LVM" so LVM can use it. Using `fdisk`, which type code applies?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command creates a 500 MiB logical volume named `lvlogs` in volume group `vgdata`?$rh2$, $rh2$[{"id":"a","text":"lvcreate -L 500M -n lvlogs vgdata"},{"id":"b","text":"lvcreate -n vgdata -L 500M lvlogs"},{"id":"c","text":"lvcreate vgdata --size lvlogs 500"},{"id":"d","text":"vgcreate -L 500M lvlogs vgdata"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`lvcreate -L 500M -n lvlogs vgdata` sets size with `-L`, name with `-n`, and takes the VG as the final argument. The other orderings/options are invalid, and `vgcreate` makes a volume group, not an LV.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command creates a 500 MiB logical volume named `lvlogs` in volume group `vgdata`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You want to grow logical volume `/dev/vgapp/lvdata` to use ALL remaining free space in the volume group and resize the XFS at the same time. Which command does this in one step?$rh2$, $rh2$[{"id":"a","text":"lvextend -l +100%FREE -r /dev/vgapp/lvdata"},{"id":"b","text":"lvextend -L 100% /dev/vgapp/lvdata"},{"id":"c","text":"lvresize --all /dev/vgapp/lvdata"},{"id":"d","text":"vgextend -l +100%FREE /dev/vgapp/lvdata"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`-l +100%FREE` consumes all free extents and `-r` (`--resizefs`) automatically grows the file system after extending. `-L 100%` is not valid sizing, `lvresize --all` is not valid, and `vgextend` adds PVs.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want to grow logical volume `/dev/vgapp/lvdata` to use ALL remaining free space in the volume group and resize the XFS at the same time. Which command does this in one step?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command deactivates swap on `/dev/vg01/lvswap` so the device can be removed?$rh2$, $rh2$[{"id":"a","text":"swapoff /dev/vg01/lvswap"},{"id":"b","text":"swapon -d /dev/vg01/lvswap"},{"id":"c","text":"umount /dev/vg01/lvswap"},{"id":"d","text":"mkswap -off /dev/vg01/lvswap"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`swapoff <device>` deactivates the swap area so it is no longer in use. Swap is not unmounted with `umount`, `swapon -d` is for discard not disabling, and `mkswap -off` is not valid.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command deactivates swap on `/dev/vg01/lvswap` so the device can be removed?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 4, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about partitioning tools on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"`parted` can create both MBR (msdos) and GPT partition tables."},{"id":"b","text":"`gdisk` is specifically designed for GPT partition tables."},{"id":"c","text":"`fdisk` in current RHEL supports GPT as well as MBR."},{"id":"d","text":"`mkfs` is the tool used to create a partition table."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$`parted` supports msdos and gpt labels, `gdisk` is GPT-focused, and modern `fdisk` handles GPT. `mkfs` creates a FILE SYSTEM on an existing partition, not a partition table, so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about partitioning tools on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command removes a logical volume `/dev/vgdata/lvold` permanently?$rh2$, $rh2$[{"id":"a","text":"lvremove /dev/vgdata/lvold"},{"id":"b","text":"lvreduce -L 0 /dev/vgdata/lvold"},{"id":"c","text":"vgremove /dev/vgdata/lvold"},{"id":"d","text":"rm -f /dev/vgdata/lvold"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`lvremove` deletes the logical volume and frees its extents back to the VG. `lvreduce -L 0` is invalid, `vgremove` deletes the whole volume group, and `rm` on the device node does not remove the LVM metadata.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command removes a logical volume `/dev/vgdata/lvold` permanently?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command mounts the file system on `/dev/vgdata/lvweb` at the existing directory `/srv/web`?$rh2$, $rh2$[{"id":"a","text":"mount /dev/vgdata/lvweb /srv/web"},{"id":"b","text":"mount /srv/web /dev/vgdata/lvweb"},{"id":"c","text":"mount -o /dev/vgdata/lvweb=/srv/web"},{"id":"d","text":"mountpoint /dev/vgdata/lvweb /srv/web"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The syntax is `mount <device> <mountpoint>`, so `mount /dev/vgdata/lvweb /srv/web`. Option B reverses the arguments, the `-o` form is invalid, and `mountpoint` only tests whether a path is a mount point.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command mounts the file system on `/dev/vgdata/lvweb` at the existing directory `/srv/web`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command unmounts `/srv/web`, returning an error if the file system is busy (no force)?$rh2$, $rh2$[{"id":"a","text":"umount /srv/web"},{"id":"b","text":"umount -l /srv/web"},{"id":"c","text":"umount -f /srv/web"},{"id":"d","text":"unmount /srv/web"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Plain `umount /srv/web` cleanly unmounts and fails (without forcing) if the FS is busy. `-l` is a lazy detach, `-f` forces (typically for network FS), and `unmount` is not the correct command name.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command unmounts `/srv/web`, returning an error if the file system is busy (no force)?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command checks and repairs an UNMOUNTED ext4 file system on `/dev/vdb1`?$rh2$, $rh2$[{"id":"a","text":"fsck.ext4 -y /dev/vdb1"},{"id":"b","text":"xfs_repair /dev/vdb1"},{"id":"c","text":"fsck.ext4 /dev/vdb1 (while mounted)"},{"id":"d","text":"tune2fs -c 0 /dev/vdb1"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`fsck.ext4 -y /dev/vdb1` (i.e. `e2fsck`) checks/repairs an UNMOUNTED ext4 file system, answering yes to fixes. `xfs_repair` is for XFS, checking a mounted FS risks corruption, and `tune2fs -c 0` only disables the mount-count check.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command checks and repairs an UNMOUNTED ext4 file system on `/dev/vdb1`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command tells you the file-system type of an already-mounted directory `/home`?$rh2$, $rh2$[{"id":"a","text":"findmnt /home"},{"id":"b","text":"df /home --type"},{"id":"c","text":"lsblk /home"},{"id":"d","text":"file /home"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`findmnt /home` shows the source device, mount point, FS type, and options. `df /home --type` is invalid syntax, `lsblk` takes a device not a path, and `file /home` just says it is a directory.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command tells you the file-system type of an already-mounted directory `/home`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You want a directory `/team` where every new file is owned by the group `team` automatically. Which special permission bit accomplishes this?$rh2$, $rh2$[{"id":"a","text":"The setgid bit: chmod g+s /team"},{"id":"b","text":"The sticky bit: chmod +t /team"},{"id":"c","text":"The setuid bit: chmod u+s /team"},{"id":"d","text":"A default ACL is the only possible way"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The setgid bit on a directory makes new files/subdirs inherit the directory's GROUP ownership. The sticky bit restricts deletion, setuid affects executables, and while a default ACL can also work, setgid is the classic intended mechanism.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want a directory `/team` where every new file is owned by the group `team` automatically. Which special permission bit accomplishes this?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which `/etc/fstab` mount option mounts a file system read-only?$rh2$, $rh2$[{"id":"a","text":"ro"},{"id":"b","text":"rw"},{"id":"c","text":"noexec"},{"id":"d","text":"nosuid"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`ro` mounts the file system read-only. `rw` is read-write, `noexec` blocks executing binaries, and `nosuid` ignores setuid/setgid bits — none of those make it read-only.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which `/etc/fstab` mount option mounts a file system read-only?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$Which command mounts an NFSv4 export with the option to retry indefinitely in the background if the server is temporarily unreachable?$rh2$, $rh2$[{"id":"a","text":"mount -t nfs -o bg,vers=4 nfssrv:/exp /mnt/exp"},{"id":"b","text":"mount -t nfs -o sync nfssrv:/exp /mnt/exp"},{"id":"c","text":"mount -t nfs -o hard,nolock,async nfssrv:/exp /mnt/exp"},{"id":"d","text":"mount -t cifs -o bg nfssrv:/exp /mnt/exp"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The `bg` option retries the mount in the background, and `vers=4` selects NFSv4. `sync` only forces synchronous writes, `cifs` is the wrong type for NFS, and the `nolock,async` combo does not provide background retry.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/mounting-nfs-shares_managing-file-systems","label":"RHEL 9 — Deploying and using NFS / autofs"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command mounts an NFSv4 export with the option to retry indefinitely in the background if the server is temporarily unreachable?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 2, $rh2$TRUE_FALSE$rh2$::"QType", $rh2$On RHEL 9, `dnf info httpd` displays the version, size, and summary of the httpd package.$rh2$, $rh2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`dnf info httpd` prints package metadata such as name, version, size, and summary (equivalent to `rpm -qi` for an installed package), so the statement is true.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$On RHEL 9, `dnf info httpd` displays the version, size, and summary of the httpd package.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command finds out which installed package provides the file `/usr/sbin/httpd`?$rh2$, $rh2$[{"id":"a","text":"rpm -qf /usr/sbin/httpd"},{"id":"b","text":"rpm -ql /usr/sbin/httpd"},{"id":"c","text":"dnf list /usr/sbin/httpd"},{"id":"d","text":"rpm -qa /usr/sbin/httpd"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`rpm -qf <file>` queries which package OWNS the file (`dnf provides /usr/sbin/httpd` also works). `rpm -ql` lists a package's files, `dnf list` lists packages by name, and `rpm -qa` lists all installed packages.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command finds out which installed package provides the file `/usr/sbin/httpd`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command updates ALL installed packages to their latest available versions non-interactively?$rh2$, $rh2$[{"id":"a","text":"dnf -y upgrade"},{"id":"b","text":"dnf refresh --all"},{"id":"c","text":"rpm -U *"},{"id":"d","text":"dnf reinstall all"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`dnf -y upgrade` (alias `dnf -y update`) upgrades every package, auto-confirming with `-y`. `dnf refresh` is not a subcommand, `rpm -U *` would not resolve dependencies, and `dnf reinstall` only re-installs existing versions.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command updates ALL installed packages to their latest available versions non-interactively?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which `nmcli` command adds a DNS server 8.8.8.8 to the existing connection `ens3` and keeps it persistent?$rh2$, $rh2$[{"id":"a","text":"nmcli con mod ens3 ipv4.dns 8.8.8.8 ; nmcli con up ens3"},{"id":"b","text":"nmcli dns add ens3 8.8.8.8"},{"id":"c","text":"echo nameserver 8.8.8.8 >> /etc/resolv.conf (persistent)"},{"id":"d","text":"nmcli con mod ens3 dns=8.8.8.8 --temp"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Setting `ipv4.dns` on the connection profile and re-activating it (`con up`) persists the DNS server. Editing `/etc/resolv.conf` directly is overwritten by NetworkManager, and the other nmcli forms are invalid.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_networking/index","label":"RHEL 9 — Configuring and managing networking"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which `nmcli` command adds a DNS server 8.8.8.8 to the existing connection `ens3` and keeps it persistent?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You must temporarily add the kernel argument `systemd.unit=rescue.target` for ONLY the next boot. Which approach fits?$rh2$, $rh2$[{"id":"a","text":"At the GRUB menu, press `e`, append the argument to the linux line, and press Ctrl+x to boot once"},{"id":"b","text":"grubby --update-kernel=ALL --args=\"systemd.unit=rescue.target\""},{"id":"c","text":"Edit /etc/default/grub and run grub2-mkconfig"},{"id":"d","text":"sysctl -w systemd.unit=rescue.target"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Editing the GRUB entry interactively with `e` and booting with Ctrl+x applies the argument for that single boot only. The `grubby` and `/etc/default/grub` options make PERSISTENT changes, and `sysctl` is unrelated to boot arguments.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_monitoring_and_updating_the_kernel/index","label":"RHEL 9 — Managing the boot process / rescue & emergency targets"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You must temporarily add the kernel argument `systemd.unit=rescue.target` for ONLY the next boot. Which approach fits?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$Which command removes the kernel argument `quiet` from all boot entries persistently?$rh2$, $rh2$[{"id":"a","text":"grubby --update-kernel=ALL --remove-args=\"quiet\""},{"id":"b","text":"grubby --delete-arg quiet"},{"id":"c","text":"grub2-editenv - unset quiet"},{"id":"d","text":"sed -i /quiet/d /proc/cmdline"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`grubby --update-kernel=ALL --remove-args="quiet"` strips the argument from every boot entry persistently. `--delete-arg` is not the option name, `grub2-editenv` manages environment variables, and `/proc/cmdline` is read-only.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_monitoring_and_updating_the_kernel/index","label":"RHEL 9 — Managing the boot process / rescue & emergency targets"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command removes the kernel argument `quiet` from all boot entries persistently?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists all containers (including stopped ones) for the current rootless user?$rh2$, $rh2$[{"id":"a","text":"podman ps -a"},{"id":"b","text":"podman ps"},{"id":"c","text":"podman images -a"},{"id":"d","text":"podman list --stopped"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`podman ps -a` lists all containers including exited ones. `podman ps` alone shows only running containers, `podman images` lists images, and `podman list --stopped` is not valid syntax.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/building_running_and_managing_containers/index","label":"RHEL 9 — Building, running, and managing containers"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists all containers (including stopped ones) for the current rootless user?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command mounts a host directory `/srv/data` into a rootless container at `/data` with a correct SELinux relabel?$rh2$, $rh2$[{"id":"a","text":"podman run -v /srv/data:/data:Z nginx"},{"id":"b","text":"podman run -v /srv/data:/data:ro,noselinux nginx"},{"id":"c","text":"podman run --mount /srv/data /data nginx"},{"id":"d","text":"podman run -v /srv/data=/data nginx"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The `:Z` suffix on a `-v` bind mount tells Podman to relabel the host path with a private SELinux container label so the container can access it. The other forms use invalid syntax or disable SELinux improperly.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/building_running_and_managing_containers/index","label":"RHEL 9 — Building, running, and managing containers"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command mounts a host directory `/srv/data` into a rootless container at `/data` with a correct SELinux relabel?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about chrony on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"The configuration file is `/etc/chrony.conf`."},{"id":"b","text":"`chronyc sources` lists the time sources chrony is using."},{"id":"c","text":"The `iburst` option speeds up initial synchronization."},{"id":"d","text":"chrony cannot act as an NTP server for other hosts."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$chrony reads `/etc/chrony.conf`, `chronyc sources` lists sources, and `iburst` accelerates the first sync. chrony CAN serve time to clients via the `allow` directive, so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/using-chrony-to-configure-ntp_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: chrony time sync"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about chrony on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command sets (or changes) the password for user `erin`, prompting for the new password?$rh2$, $rh2$[{"id":"a","text":"passwd erin"},{"id":"b","text":"chage erin"},{"id":"c","text":"usermod -p erin"},{"id":"d","text":"useradd -p erin"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`passwd erin` (run as root) interactively sets erin's password. `chage` manages aging, `usermod -p` expects a pre-hashed value (not a prompt), and `useradd` creates a new account.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command sets (or changes) the password for user `erin`, prompting for the new password?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command displays the password-aging information (last change, expiry, etc.) for user `frank`?$rh2$, $rh2$[{"id":"a","text":"chage -l frank"},{"id":"b","text":"passwd -S frank only shows aging"},{"id":"c","text":"id frank"},{"id":"d","text":"getent aging frank"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`chage -l frank` lists last-change date, min/max age, warning, and expiry. `passwd -S` shows only status (locked/expired summary), `id` shows UID/GID, and `getent aging` is not valid.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command displays the password-aging information (last change, expiry, etc.) for user `frank`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command changes the login shell of user `gina` to `/bin/sh`?$rh2$, $rh2$[{"id":"a","text":"usermod -s /bin/sh gina"},{"id":"b","text":"chsh -s gina /bin/sh"},{"id":"c","text":"usermod -shell /bin/sh gina"},{"id":"d","text":"passwd -s /bin/sh gina"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`usermod -s /bin/sh gina` updates the shell field in `/etc/passwd` (root for any user). `chsh -s` syntax is `chsh -s /bin/sh gina` (the option shown is reversed), `-shell` is not valid, and `passwd -s` shows status.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command changes the login shell of user `gina` to `/bin/sh`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 4, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about user and group management on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"Each user has exactly one primary group and zero or more supplementary groups."},{"id":"b","text":"Default settings for new accounts come from `/etc/login.defs` and `/etc/default/useradd`."},{"id":"c","text":"`id <user>` shows the user's UID, primary GID, and group memberships."},{"id":"d","text":"Deleting a user with `userdel` always removes their home directory automatically."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$A user has one primary group plus optional supplementary groups; defaults live in `/etc/login.defs` and `/etc/default/useradd`; `id` summarizes IDs/groups. `userdel` removes the home directory ONLY with `-r`, so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about user and group management on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows a detailed SELinux status report including current mode, config-file mode, and policy?$rh2$, $rh2$[{"id":"a","text":"sestatus"},{"id":"b","text":"getenforce -v"},{"id":"c","text":"semanage status"},{"id":"d","text":"selinux --report"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`sestatus` prints SELinux status, mounted FS, current/config mode, and loaded policy. `getenforce` only prints one word (no `-v`), and `semanage status`/`selinux --report` are not valid.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows a detailed SELinux status report including current mode, config-file mode, and policy?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Apache must listen on the non-standard port 8888. With SELinux enforcing, which command adds 8888 to the allowed http port type persistently?$rh2$, $rh2$[{"id":"a","text":"semanage port -a -t http_port_t -p tcp 8888"},{"id":"b","text":"setsebool -P httpd_port 8888"},{"id":"c","text":"firewall-cmd --add-port=8888/tcp"},{"id":"d","text":"chcon -t http_port_t 8888"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`semanage port -a -t http_port_t -p tcp 8888` registers the new port with the SELinux policy so httpd may bind it. `setsebool` toggles booleans, firewalld only handles packet filtering, and `chcon` relabels files (ports are not files).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Apache must listen on the non-standard port 8888. With SELinux enforcing, which command adds 8888 to the allowed http port type persistently?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists all SELinux booleans and their current on/off state?$rh2$, $rh2$[{"id":"a","text":"getsebool -a"},{"id":"b","text":"setsebool -a"},{"id":"c","text":"semanage boolean -d"},{"id":"d","text":"sestatus -b"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`getsebool -a` lists every boolean with its state (`semanage boolean -l` is an alternative). `setsebool -a` is invalid (it SETs a named boolean), `semanage boolean -d` deletes, and `sestatus -b` is not a valid option.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists all SELinux booleans and their current on/off state?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command permanently changes the default firewalld zone to `work`?$rh2$, $rh2$[{"id":"a","text":"firewall-cmd --set-default-zone=work"},{"id":"b","text":"firewall-cmd --permanent --zone=work --default"},{"id":"c","text":"firewall-cmd --change-zone work"},{"id":"d","text":"firewall-cmd --add-zone=work --default"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`firewall-cmd --set-default-zone=work` immediately and permanently sets the default zone (no separate `--permanent`/`--reload` needed for this specific command). The other option strings are not valid firewalld syntax.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/securing_networks/using-and-configuring-firewalld_securing-networks","label":"RHEL 9 — Securing networks: using and configuring firewalld"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p2$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command permanently changes the default firewalld zone to `work`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$In bash, which glob pattern matches every file in the current directory that ends in `.log`?$rh2$, $rh2$[{"id":"a","text":"*.log"},{"id":"b","text":"?.log only"},{"id":"c","text":"%.log"},{"id":"d","text":"log.*"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`*` matches any sequence of characters, so `*.log` matches all names ending in `.log`. `?` matches exactly one character, `%` has no globbing meaning in bash, and `log.*` matches names that START with `log.`.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$In bash, which glob pattern matches every file in the current directory that ends in `.log`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about bash input/output redirection.$rh2$, $rh2$[{"id":"a","text":"`>>` appends stdout to a file instead of truncating it."},{"id":"b","text":"`2>&1` redirects stderr to wherever stdout currently points."},{"id":"c","text":"`<` reads a command's standard input from a file."},{"id":"d","text":"`|` redirects stdout to a file, overwriting it."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$`>>` appends, `2>&1` ties stderr to stdout's current target, and `<` feeds stdin from a file. `|` pipes stdout to ANOTHER COMMAND, not to a file (that would be `>`), so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about bash input/output redirection.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You generate an SSH key pair and want to enable passwordless login to `host2` for the current user. Which command installs your public key into the remote `authorized_keys`?$rh2$, $rh2$[{"id":"a","text":"ssh-copy-id user@host2"},{"id":"b","text":"scp ~/.ssh/id_rsa user@host2:/"},{"id":"c","text":"ssh-keygen -R host2"},{"id":"d","text":"ssh-add host2"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`ssh-copy-id` appends your PUBLIC key to the remote `~/.ssh/authorized_keys` with correct permissions. Copying the PRIVATE key is wrong/insecure, `ssh-keygen -R` removes a known_hosts entry, and `ssh-add` loads keys into the local agent.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You generate an SSH key pair and want to enable passwordless login to `host2` for the current user. Which command installs your public key into the remote `authorized_keys`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You have forgotten the root password. On RHEL 9, which boot-time approach lets you reset it?$rh2$, $rh2$[{"id":"a","text":"Edit the GRUB entry to add `rd.break`, then remount sysroot rw, run `chroot /sysroot`, `passwd`, and create `/.autorelabel`"},{"id":"b","text":"Boot normally and run `passwd root` as an unprivileged user"},{"id":"c","text":"Reinstall the operating system"},{"id":"d","text":"Press Ctrl+Alt+Del at the login screen"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Adding `rd.break` drops to the initramfs; you remount `/sysroot` rw, `chroot`, set the password, and touch `/.autorelabel` so SELinux relabels on the next boot. An unprivileged user cannot change root's password, and reinstalling is unnecessary.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_monitoring_and_updating_the_kernel/index","label":"RHEL 9 — Managing the boot process / rescue & emergency targets"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You have forgotten the root password. On RHEL 9, which boot-time approach lets you reset it?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command switches the CURRENT running system into rescue mode without rebooting?$rh2$, $rh2$[{"id":"a","text":"systemctl isolate rescue.target"},{"id":"b","text":"systemctl set-default rescue.target"},{"id":"c","text":"systemctl enable rescue.target"},{"id":"d","text":"systemctl rescue --boot"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`systemctl isolate rescue.target` transitions the live system to the rescue target immediately. `set-default` only affects future boots, `enable` does not isolate, and `systemctl rescue --boot` is not valid syntax (`systemctl rescue` works but the `--boot` flag does not).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_monitoring_and_updating_the_kernel/index","label":"RHEL 9 — Managing the boot process / rescue & emergency targets"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command switches the CURRENT running system into rescue mode without rebooting?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows a continuously updating, interactive view of running processes and their CPU/memory usage?$rh2$, $rh2$[{"id":"a","text":"top"},{"id":"b","text":"ps -ef --once"},{"id":"c","text":"journalctl -f"},{"id":"d","text":"systemctl status --top"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`top` provides a live, refreshing process monitor. `ps -ef` is a one-time snapshot (and `--once` is not a real option), `journalctl -f` follows logs, and `systemctl status --top` is not a valid command.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows a continuously updating, interactive view of running processes and their CPU/memory usage?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command displays block devices with their mount points and file-system types in a tree view?$rh2$, $rh2$[{"id":"a","text":"lsblk -f"},{"id":"b","text":"df -i"},{"id":"c","text":"fdisk -t"},{"id":"d","text":"mount --tree"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`lsblk -f` lists block devices in a tree with FSTYPE, LABEL, UUID, and MOUNTPOINTS. `df -i` shows inode usage of mounted file systems, `fdisk -t` is not valid, and `mount --tree` is not a real option.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command displays block devices with their mount points and file-system types in a tree view?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$You want a VDO-style deduplicated/compressed volume in RHEL 9. Which approach is supported in RHEL 9?$rh2$, $rh2$[{"id":"a","text":"Create an LVM VDO logical volume (`lvcreate --type vdo`) on a volume group"},{"id":"b","text":"Run `vdo create` from the standalone vdo package, which is the only RHEL 9 method"},{"id":"c","text":"Use `mkfs.vdo /dev/vdb` directly"},{"id":"d","text":"VDO is not available on RHEL 9 at all"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$In RHEL 9 VDO is integrated with LVM — you create it as an LVM VDO LV (`lvcreate --type vdo`). The standalone `vdo` command from RHEL 8 is no longer the supported path, `mkfs.vdo` is not a command, and VDO IS available (just LVM-managed).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want a VDO-style deduplicated/compressed volume in RHEL 9. Which approach is supported in RHEL 9?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$To make a newly created swap LV `/dev/vg01/lvswap` activate automatically at every boot, you should:$rh2$, $rh2$[{"id":"a","text":"Add a line `/dev/vg01/lvswap none swap defaults 0 0` to /etc/fstab"},{"id":"b","text":"Run `swapon` once and rely on it persisting"},{"id":"c","text":"Add the device to /etc/crypttab"},{"id":"d","text":"Create a systemd timer that runs swapon"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$An `/etc/fstab` entry with fs type `swap` and mountpoint `none` makes the swap area persistent across reboots. A one-off `swapon` does not persist, `/etc/crypttab` is for encrypted devices, and a timer is unnecessary and non-standard.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$To make a newly created swap LV `/dev/vg01/lvswap` activate automatically at every boot, you should:$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$After adding a new line to `/etc/fstab`, which command mounts ALL listed file systems that are not yet mounted, letting you validate the entry without rebooting?$rh2$, $rh2$[{"id":"a","text":"mount -a"},{"id":"b","text":"mount --remount /"},{"id":"c","text":"systemctl daemon-reexec"},{"id":"d","text":"umount -a"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`mount -a` attempts to mount every fstab entry not already mounted — the standard way to test new entries safely. `--remount /` only re-applies root options, `daemon-reexec` re-executes systemd, and `umount -a` unmounts everything.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$After adding a new line to `/etc/fstab`, which command mounts ALL listed file systems that are not yet mounted, letting you validate the entry without rebooting?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You must mount the NFS export `nfs.example.com:/exports/data` at `/mnt/data` right now for testing. Which command does this?$rh2$, $rh2$[{"id":"a","text":"mount -t nfs nfs.example.com:/exports/data /mnt/data"},{"id":"b","text":"mount -t xfs nfs.example.com:/exports/data /mnt/data"},{"id":"c","text":"mount --nfs /exports/data /mnt/data"},{"id":"d","text":"nfs-mount nfs.example.com /mnt/data"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`mount -t nfs server:/export /mountpoint` is the correct syntax (requires the `nfs-utils` package). `xfs` is the wrong type for a network export, and `--nfs` / `nfs-mount` are not valid commands.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/mounting-nfs-shares_managing-file-systems","label":"RHEL 9 — Deploying and using NFS / autofs"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You must mount the NFS export `nfs.example.com:/exports/data` at `/mnt/data` right now for testing. Which command does this?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command sets a DEFAULT ACL on directory `/data/projects` so that newly created files inherit read access for group `team`?$rh2$, $rh2$[{"id":"a","text":"setfacl -m d:g:team:r-- /data/projects"},{"id":"b","text":"setfacl -m g:team:r-- /data/projects"},{"id":"c","text":"chmod g+s /data/projects"},{"id":"d","text":"chacl team:r /data/projects"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The `d:` prefix denotes a DEFAULT ACL entry, which new files/dirs inherit. Without `d:` it is only an access ACL on the directory itself. `chmod g+s` sets the setgid bit (group inheritance, not ACL), and `chacl` is not standard on RHEL.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command sets a DEFAULT ACL on directory `/data/projects` so that newly created files inherit read access for group `team`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists all installed packages whose name contains "kernel"?$rh2$, $rh2$[{"id":"a","text":"dnf list installed | grep kernel"},{"id":"b","text":"dnf remove kernel"},{"id":"c","text":"rpm --search kernel"},{"id":"d","text":"dnf info --all kernel"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`dnf list installed` enumerates installed packages; piping to `grep kernel` filters by name. `dnf remove` would uninstall, `rpm --search` is not a valid option, and `dnf info --all` is not the right query form.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists all installed packages whose name contains "kernel"?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You need to add an extra NTP server `time.example.com` to chrony and apply it. Which steps are correct on RHEL 9?$rh2$, $rh2$[{"id":"a","text":"Add `server time.example.com iburst` to /etc/chrony.conf, then `systemctl restart chronyd`"},{"id":"b","text":"Add the server to /etc/ntp.conf, then `systemctl restart ntpd`"},{"id":"c","text":"Run `chronyc add time.example.com` which is permanent by itself"},{"id":"d","text":"Edit /etc/resolv.conf to add the time server"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$chrony reads `/etc/chrony.conf`; adding a `server ... iburst` line and restarting `chronyd` applies it persistently. RHEL 9 uses chrony (not ntpd/ntp.conf), `chronyc add` changes are runtime-only, and `/etc/resolv.conf` is for DNS.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/using-chrony-to-configure-ntp_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: chrony time sync"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You need to add an extra NTP server `time.example.com` to chrony and apply it. Which steps are correct on RHEL 9?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command pulls the `registry.access.redhat.com/ubi9/ubi` image and runs an interactive rootless container with a bash shell?$rh2$, $rh2$[{"id":"a","text":"podman run -it registry.access.redhat.com/ubi9/ubi /bin/bash"},{"id":"b","text":"podman pull --run ubi9 bash"},{"id":"c","text":"docker exec -it ubi9 bash"},{"id":"d","text":"podman create ubi9 --shell"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`podman run -it <image> /bin/bash` pulls the image if absent and starts an interactive (`-i -t`) container — rootless by default for a normal user. `podman pull --run` is invalid, `docker exec` attaches to an EXISTING container, and `podman create` does not start it.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/building_running_and_managing_containers/index","label":"RHEL 9 — Building, running, and managing containers"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command pulls the `registry.access.redhat.com/ubi9/ubi` image and runs an interactive rootless container with a bash shell?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$A rootless container must keep running after the user logs out and start at system boot. Besides a generated systemd user unit, which command enables this?$rh2$, $rh2$[{"id":"a","text":"loginctl enable-linger <username>"},{"id":"b","text":"systemctl enable getty@tty1"},{"id":"c","text":"usermod -s /sbin/nologin <username>"},{"id":"d","text":"podman run --keep-alive"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`loginctl enable-linger <user>` lets that user's systemd user instance (and its containers) run without an active login and start at boot. The getty unit is unrelated, `nologin` would block login entirely, and `--keep-alive` is not a podman option.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/building_running_and_managing_containers/index","label":"RHEL 9 — Building, running, and managing containers"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$A rootless container must keep running after the user logs out and start at system boot. Besides a generated systemd user unit, which command enables this?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command locks the account of user `dan` so he cannot log in with a password, without deleting the account?$rh2$, $rh2$[{"id":"a","text":"usermod -L dan"},{"id":"b","text":"userdel dan"},{"id":"c","text":"passwd -d dan"},{"id":"d","text":"chage -E -1 dan"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`usermod -L` (or `passwd -l`) locks the account by disabling the password hash. `userdel` deletes the account, `passwd -d` REMOVES the password (allowing empty-password login depending on PAM), and `chage -E -1` removes account expiry — the opposite effect.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command locks the account of user `dan` so he cannot log in with a password, without deleting the account?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You want all NEW users to receive a 60-day maximum password age by default. Which file should you configure?$rh2$, $rh2$[{"id":"a","text":"/etc/login.defs (set PASS_MAX_DAYS 60)"},{"id":"b","text":"/etc/passwd"},{"id":"c","text":"/etc/shells"},{"id":"d","text":"/etc/profile"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`/etc/login.defs` defines defaults like `PASS_MAX_DAYS` applied to newly created accounts. `/etc/passwd` lists accounts (no aging policy), `/etc/shells` lists valid shells, and `/etc/profile` is a login shell script.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You want all NEW users to receive a 60-day maximum password age by default. Which file should you configure?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows the CURRENT SELinux mode (enforcing, permissive, or disabled)?$rh2$, $rh2$[{"id":"a","text":"getenforce"},{"id":"b","text":"setenforce"},{"id":"c","text":"sestatus --set"},{"id":"d","text":"selinuxctl mode"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`getenforce` prints the current mode; `sestatus` also shows it with more detail. `setenforce` CHANGES the mode (0/1), `sestatus --set` is invalid, and `selinuxctl` is not a command.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows the CURRENT SELinux mode (enforcing, permissive, or disabled)?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You moved a web app to a non-standard document root `/web` and Apache (SELinux enforcing) is denied access. Which command persistently labels `/web` (and below) with the correct context so it survives a relabel?$rh2$, $rh2$[{"id":"a","text":"semanage fcontext -a -t httpd_sys_content_t \"/web(/.*)?\" ; restorecon -Rv /web"},{"id":"b","text":"chcon -t httpd_sys_content_t /web only"},{"id":"c","text":"setenforce 0"},{"id":"d","text":"restorecon -Rv /web only"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`semanage fcontext -a` records the context rule in policy so it is PERSISTENT, then `restorecon` applies it. `chcon` alone changes the label but is lost on a full relabel, `restorecon` alone has no rule to apply for a custom path, and `setenforce 0` just disables enforcement.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You moved a web app to a non-standard document root `/web` and Apache (SELinux enforcing) is denied access. Which command persistently labels `/web` (and below) with the correct context so it survives a relabel?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 1, $rh2$TRUE_FALSE$rh2$::"QType", $rh2$The command `mkdir -p /srv/app/conf` creates any missing parent directories and does not error if the path already exists.$rh2$, $rh2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`mkdir -p` creates intermediate parent directories as needed and exits successfully even when the directory already exists, so the statement is true.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$The command `mkdir -p /srv/app/conf` creates any missing parent directories and does not error if the path already exists.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command moves and renames the file `old.txt` to `/tmp/new.txt`?$rh2$, $rh2$[{"id":"a","text":"mv old.txt /tmp/new.txt"},{"id":"b","text":"cp old.txt /tmp/new.txt"},{"id":"c","text":"rename old.txt /tmp/new.txt"},{"id":"d","text":"mv -c old.txt /tmp/new.txt"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`mv old.txt /tmp/new.txt` relocates and renames in a single operation, removing the source. `cp` would leave the original behind, the `rename` syntax shown is not the move idiom, and `mv -c` is not a valid option.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command moves and renames the file `old.txt` to `/tmp/new.txt`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command searches the entire filesystem for files literally named `core` (regular files) starting from `/`?$rh2$, $rh2$[{"id":"a","text":"find / -type f -name core"},{"id":"b","text":"find / -name -type f core"},{"id":"c","text":"locate -type f core"},{"id":"d","text":"grep -r core /"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`find / -type f -name core` walks from `/` matching regular files named exactly `core`. The second option misorders find arguments, `locate` has no `-type`, and `grep -r` searches file CONTENTS rather than names.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command searches the entire filesystem for files literally named `core` (regular files) starting from `/`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows the last 20 lines of `/var/log/secure`?$rh2$, $rh2$[{"id":"a","text":"tail -n 20 /var/log/secure"},{"id":"b","text":"head -n 20 /var/log/secure"},{"id":"c","text":"cat -20 /var/log/secure"},{"id":"d","text":"less +20 /var/log/secure"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`tail -n 20` prints the final 20 lines. `head -n 20` shows the FIRST 20, `cat -20` is invalid, and `less +20` jumps to line 20 but does not limit output to 20 lines.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows the last 20 lines of `/var/log/secure`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about getting help on RHEL 9 commands.$rh2$, $rh2$[{"id":"a","text":"`man 5 crontab` opens the file-format (section 5) man page for crontab."},{"id":"b","text":"`command --help` typically prints a brief usage summary."},{"id":"c","text":"`apropos copy` searches man page descriptions for the word \"copy\"."},{"id":"d","text":"`man -k` is unrelated to keyword searching."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$Man sections can be requested explicitly (`man 5 crontab`), most tools support `--help`, and `apropos` searches man descriptions. `man -k` is actually the SAME as `apropos` (keyword search), so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about getting help on RHEL 9 commands.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command securely copies the local directory `site/` recursively to `/var/www/` on remote host `web1` as user `deploy`?$rh2$, $rh2$[{"id":"a","text":"scp -r site/ deploy@web1:/var/www/"},{"id":"b","text":"scp site/ deploy@web1:/var/www/"},{"id":"c","text":"cp -r site/ deploy@web1:/var/www/"},{"id":"d","text":"scp -R deploy@web1 site/ /var/www/"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`scp -r` copies directories recursively over SSH to `user@host:/path`. Without `-r` scp refuses a directory, `cp` is local-only, and `-R` (uppercase) is not the scp recurse flag and the argument order is wrong.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command securely copies the local directory `site/` recursively to `/var/www/` on remote host `web1` as user `deploy`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Understand and Use Essential Tools$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$Which command pipeline shows the 5 largest entries (by size) directly under `/var` in human-readable form?$rh2$, $rh2$[{"id":"a","text":"du -sh /var/* | sort -rh | head -n 5"},{"id":"b","text":"du -sh /var/* | sort -n | tail -n 5"},{"id":"c","text":"ls -lS /var | head -5"},{"id":"d","text":"df -h /var/* | sort -r | head -5"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`du -sh /var/*` sizes each entry, `sort -rh` sorts human-readable sizes in reverse (largest first), and `head -n 5` keeps the top five. `sort -n` mis-sorts suffixed sizes, `ls -lS` does not sum directory trees, and `df` reports file systems.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command pipeline shows the 5 largest entries (by size) directly under `/var` in human-readable form?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command reloads the configuration of the running `nginx` service WITHOUT fully restarting it (if the unit supports reload)?$rh2$, $rh2$[{"id":"a","text":"systemctl reload nginx"},{"id":"b","text":"systemctl restart nginx"},{"id":"c","text":"systemctl refresh nginx"},{"id":"d","text":"systemctl reexec nginx"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`systemctl reload nginx` triggers the unit's ExecReload (re-read config, keep the process). `restart` stops and starts (drops connections), and `refresh`/`reexec` are not valid per-service actions.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command reloads the configuration of the running `nginx` service WITHOUT fully restarting it (if the unit supports reload)?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command prevents the `bluetooth` service from being started either manually OR automatically (the strongest disable)?$rh2$, $rh2$[{"id":"a","text":"systemctl mask bluetooth"},{"id":"b","text":"systemctl disable bluetooth"},{"id":"c","text":"systemctl stop bluetooth"},{"id":"d","text":"systemctl freeze bluetooth"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`systemctl mask` links the unit to `/dev/null` so it cannot be started by any means until unmasked. `disable` only removes boot enablement (manual start still works), `stop` is temporary, and `freeze` suspends a running unit's processes.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command prevents the `bluetooth` service from being started either manually OR automatically (the strongest disable)?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command sends SIGHUP (often used to reload config) to the process with PID 990?$rh2$, $rh2$[{"id":"a","text":"kill -HUP 990"},{"id":"b","text":"kill -9 990"},{"id":"c","text":"kill -SIGKILL 990"},{"id":"d","text":"kill --reload 990"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`kill -HUP 990` (or `kill -1 990`) sends SIGHUP, which many daemons treat as "reload configuration". `-9`/`-SIGKILL` force-kill the process, and `--reload` is not a valid kill option.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"RHEL 9 — Configuring basic system settings"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command sends SIGHUP (often used to reload config) to the process with PID 990?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows the boot target the system will boot into by default?$rh2$, $rh2$[{"id":"a","text":"systemctl get-default"},{"id":"b","text":"systemctl default"},{"id":"c","text":"systemctl is-default"},{"id":"d","text":"runlevel --default"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`systemctl get-default` prints the unit the `default.target` symlink points to. `systemctl default` switches to that target now, `is-default` is not a command, and `runlevel` reports the current/previous runlevel only.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows the boot target the system will boot into by default?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command filters the journal to show only messages for the `sshd` unit since today?$rh2$, $rh2$[{"id":"a","text":"journalctl -u sshd --since today"},{"id":"b","text":"journalctl sshd --today"},{"id":"c","text":"journalctl -f sshd"},{"id":"d","text":"journalctl --unit=sshd --recent"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Combining `-u sshd` (unit filter) with `--since today` limits output to today's sshd entries. `journalctl sshd` treats sshd as a path, `-f` follows new entries, and `--recent` is not a valid option.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command filters the journal to show only messages for the `sshd` unit since today?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about controlling services with systemctl on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"`systemctl enable <unit>` creates the symlinks so the unit starts at boot."},{"id":"b","text":"`systemctl start <unit>` starts the unit immediately for this session."},{"id":"c","text":"`systemctl is-enabled <unit>` reports whether the unit starts at boot."},{"id":"d","text":"`systemctl enable <unit>` also starts the unit immediately."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$`enable` sets boot-time symlinks, `start` activates now, and `is-enabled` queries boot status. `enable` does NOT start the unit unless you add `--now`, so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-systemd_configuring-basic-system-settings","label":"RHEL 9 — Managing systemd services"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about controlling services with systemctl on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Operate Running Systems$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$A system boots to a black screen and you suspect a bad service. Which kernel argument added at the GRUB prompt boots into a minimal single-user-like environment for repair?$rh2$, $rh2$[{"id":"a","text":"systemd.unit=rescue.target"},{"id":"b","text":"systemd.unit=graphical.target"},{"id":"c","text":"init=/usr/lib/systemd/systemd-graphical"},{"id":"d","text":"runlevel=5"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Appending `systemd.unit=rescue.target` boots a minimal maintenance environment (root shell, basic mounts) ideal for repairs. `graphical.target` is the full GUI, the `init=` path is invalid, and `runlevel=5` is legacy syntax not used by systemd.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_monitoring_and_updating_the_kernel/index","label":"RHEL 9 — Managing the boot process / rescue & emergency targets"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$A system boots to a black screen and you suspect a bad service. Which kernel argument added at the GRUB prompt boots into a minimal single-user-like environment for repair?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists all logical volumes with their volume group and size?$rh2$, $rh2$[{"id":"a","text":"lvs"},{"id":"b","text":"lvcreate --show"},{"id":"c","text":"vgs --lv"},{"id":"d","text":"pvdisplay -l"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`lvs` prints a terse list of logical volumes (LV, VG, size, attributes); `lvdisplay` gives the verbose form. `lvcreate --show`, `vgs --lv`, and `pvdisplay -l` are not valid for listing LVs.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists all logical volumes with their volume group and size?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You need to add a 1 GiB swap FILE (not a partition) at `/swapfile`. Which sequence is correct?$rh2$, $rh2$[{"id":"a","text":"dd if=/dev/zero of=/swapfile bs=1M count=1024 ; chmod 600 /swapfile ; mkswap /swapfile ; swapon /swapfile"},{"id":"b","text":"touch /swapfile ; swapon /swapfile"},{"id":"c","text":"mkswap -f /swapfile 1G ; mount /swapfile"},{"id":"d","text":"fallocate /swapfile ; mkfs.swap /swapfile"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Allocate the file (dd or fallocate), tighten permissions to 600, run `mkswap` to write the signature, then `swapon`. An empty/touched file has no swap signature, `mkswap -f ... 1G`/`mkfs.swap` are wrong, and swap is not mounted.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You need to add a 1 GiB swap FILE (not a partition) at `/swapfile`. Which sequence is correct?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command scans all disks and activates any volume groups it finds (useful after attaching disks from another system)?$rh2$, $rh2$[{"id":"a","text":"vgscan ; vgchange -a y"},{"id":"b","text":"pvcreate --scan"},{"id":"c","text":"lvscan --activate-all"},{"id":"d","text":"vgimport --auto"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`vgscan` discovers VGs on attached disks and `vgchange -a y` activates them so their LVs become available. `pvcreate --scan` would (wrongly) try to initialize PVs, and the other options are not valid activation commands.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command scans all disks and activates any volume groups it finds (useful after attaching disks from another system)?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Using `parted` interactively, which command sequence creates a new 2 GiB primary partition starting at 1 MiB on a GPT-labelled disk?$rh2$, $rh2$[{"id":"a","text":"mkpart primary 1MiB 2049MiB"},{"id":"b","text":"mklabel primary 2GiB"},{"id":"c","text":"mkfs primary 1 2049"},{"id":"d","text":"addpart 1MiB 2GiB primary"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$In `parted`, `mkpart <name> <start> <end>` defines a partition; starting at 1MiB and ending at 2049MiB yields ~2 GiB. `mklabel` writes a partition TABLE, `mkfs` (in parted) is deprecated/unsafe, and `addpart` is not a parted command.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Using `parted` interactively, which command sequence creates a new 2 GiB primary partition starting at 1 MiB on a GPT-labelled disk?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command shows total, used, and free swap along with RAM usage in megabytes?$rh2$, $rh2$[{"id":"a","text":"free -m"},{"id":"b","text":"df -m"},{"id":"c","text":"vmstat --swap"},{"id":"d","text":"swapon -m"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`free -m` reports memory and swap totals/used/free in MiB. `df` reports disk file systems, `vmstat --swap` is not valid syntax, and `swapon -m` is not a valid option.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command shows total, used, and free swap along with RAM usage in megabytes?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$You created an LVM VDO volume `vdo0` in VG `vgvdo`. Which command formats it with XFS so VDO discard works correctly?$rh2$, $rh2$[{"id":"a","text":"mkfs.xfs -K /dev/vgvdo/vdo0"},{"id":"b","text":"mkfs.xfs /dev/vgvdo/vdo0 with full discard"},{"id":"c","text":"mkfs.vdo /dev/vgvdo/vdo0"},{"id":"d","text":"mkfs.ext4 -E nodiscard /dev/vgvdo/vdo0"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Use `mkfs.xfs -K` (do NOT discard blocks at mkfs time) on a VDO device so the thin-provisioned space is not prematurely consumed by a full discard. `mkfs.vdo` is not a command, and forcing a full discard defeats VDO's space savings.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_logical_volumes/index","label":"RHEL 9 — Configuring and managing logical volumes"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You created an LVM VDO volume `vdo0` in VG `vgvdo`. Which command formats it with XFS so VDO discard works correctly?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Configure Local Storage$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command removes a Stratis file system `fs1` from pool `pool1`?$rh2$, $rh2$[{"id":"a","text":"stratis filesystem destroy pool1 fs1"},{"id":"b","text":"stratis fs delete fs1"},{"id":"c","text":"stratis pool remove fs1"},{"id":"d","text":"lvremove pool1/fs1"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`stratis filesystem destroy <pool> <fs>` deletes the named Stratis file system. The other forms use invalid Stratis syntax, and Stratis file systems are not managed with `lvremove`.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_storage_devices/index","label":"RHEL 9 — Managing storage devices"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command removes a Stratis file system `fs1` from pool `pool1`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which `/etc/fstab` field order is correct?$rh2$, $rh2$[{"id":"a","text":"device  mountpoint  fstype  options  dump  pass"},{"id":"b","text":"mountpoint  device  options  fstype  pass  dump"},{"id":"c","text":"fstype  device  mountpoint  dump  options  pass"},{"id":"d","text":"device  fstype  options  mountpoint  pass  dump"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The six fstab fields are: file system (device/UUID), mount point, type, options, dump frequency, and fsck pass order — in that exact sequence. The other orderings are incorrect.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which `/etc/fstab` field order is correct?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which mount option in `/etc/fstab` causes the file system to be mounted automatically at boot (the default behavior you would explicitly state)?$rh2$, $rh2$[{"id":"a","text":"auto"},{"id":"b","text":"noauto"},{"id":"c","text":"user"},{"id":"d","text":"bind"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`auto` (part of `defaults`) means the file system is mounted by `mount -a`/at boot. `noauto` explicitly EXCLUDES it from automatic mounting, `user` permits unprivileged mounting, and `bind` creates a bind mount.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which mount option in `/etc/fstab` causes the file system to be mounted automatically at boot (the default behavior you would explicitly state)?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command extends an already-mounted XFS file system after its underlying LV was grown?$rh2$, $rh2$[{"id":"a","text":"xfs_growfs /mountpoint"},{"id":"b","text":"resize2fs /mountpoint"},{"id":"c","text":"xfs_admin -g /mountpoint"},{"id":"d","text":"mkfs.xfs --grow /mountpoint"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`xfs_growfs <mountpoint>` grows a mounted XFS file system to fill the enlarged device. `resize2fs` is for ext2/3/4, `xfs_admin -g` is not a grow option, and re-running `mkfs.xfs` would destroy the data.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command extends an already-mounted XFS file system after its underlying LV was grown?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command creates a bind mount so that `/data/www` also appears at `/var/www/html`?$rh2$, $rh2$[{"id":"a","text":"mount --bind /data/www /var/www/html"},{"id":"b","text":"mount -t bind /data/www /var/www/html"},{"id":"c","text":"ln -s /data/www /var/www/html"},{"id":"d","text":"mount --rbind=/data/www /var/www/html"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`mount --bind <src> <dst>` makes the source directory tree accessible at the destination. `-t bind` is not the correct syntax, a symlink is not a mount, and `--rbind=` is malformed (recursive bind is `--rbind src dst`).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command creates a bind mount so that `/data/www` also appears at `/var/www/html`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command removes ALL ACL entries from the file `/srv/report`, leaving only the standard permission bits?$rh2$, $rh2$[{"id":"a","text":"setfacl -b /srv/report"},{"id":"b","text":"setfacl -x /srv/report"},{"id":"c","text":"getfacl -r /srv/report"},{"id":"d","text":"chmod -A /srv/report"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`setfacl -b` removes all extended ACL entries (keeping the base owner/group/other bits). `-x` removes a SPECIFIC entry (and needs an entry argument), `getfacl` only displays, and `chmod -A` is not valid.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command removes ALL ACL entries from the file `/srv/report`, leaving only the standard permission bits?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You must mount NFS share `srv:/share` with NFSv4.2 explicitly. Which mount option selects that version?$rh2$, $rh2$[{"id":"a","text":"mount -t nfs -o vers=4.2 srv:/share /mnt/share"},{"id":"b","text":"mount -t nfs -o nfs4.2 srv:/share /mnt/share"},{"id":"c","text":"mount -t nfs42 srv:/share /mnt/share"},{"id":"d","text":"mount -t nfs -o version=4.2 srv:/share /mnt/share"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The mount option `vers=4.2` (or `nfsvers=4.2`) selects the NFS protocol version. `nfs4.2`, the `nfs42` type, and `version=4.2` are not recognized by `mount.nfs`.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/mounting-nfs-shares_managing-file-systems","label":"RHEL 9 — Deploying and using NFS / autofs"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You must mount NFS share `srv:/share` with NFSv4.2 explicitly. Which mount option selects that version?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Create and Configure File Systems$rh2$, 4, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about XFS vs ext4 on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"XFS is the default file system for RHEL 9 root installations."},{"id":"b","text":"XFS can be grown online but cannot be shrunk."},{"id":"c","text":"ext4 can be both grown and shrunk (offline for shrink)."},{"id":"d","text":"XFS file systems are checked and repaired with `fsck.ext4`."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$RHEL defaults to XFS, which grows online but cannot shrink; ext4 supports both grow and (offline) shrink. XFS is repaired with `xfs_repair`, not `fsck.ext4`, so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"RHEL 9 — Managing file systems"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about XFS vs ext4 on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command searches DNF repositories for packages whose name or summary mentions "nginx"?$rh2$, $rh2$[{"id":"a","text":"dnf search nginx"},{"id":"b","text":"dnf find nginx"},{"id":"c","text":"rpm -qa | dnf nginx"},{"id":"d","text":"dnf lookup nginx"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`dnf search nginx` queries repository metadata for matching package names/summaries. `dnf find`, `dnf lookup`, and the piped `rpm`/`dnf` form are not valid commands.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command searches DNF repositories for packages whose name or summary mentions "nginx"?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$You added a repo definition by creating a `.repo` file under `/etc/yum.repos.d/`. Which command lists it among the configured repositories?$rh2$, $rh2$[{"id":"a","text":"dnf repolist --all"},{"id":"b","text":"dnf addrepo --list"},{"id":"c","text":"dnf config --show-repos"},{"id":"d","text":"rpm -q repos"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`dnf repolist --all` lists every configured repository (enabled and disabled), including newly added `.repo` files. `dnf addrepo --list`, `dnf config --show-repos`, and `rpm -q repos` are not valid.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You added a repo definition by creating a `.repo` file under `/etc/yum.repos.d/`. Which command lists it among the configured repositories?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command resets the `nodejs` module so a different stream can be installed cleanly?$rh2$, $rh2$[{"id":"a","text":"dnf module reset nodejs"},{"id":"b","text":"dnf module clear nodejs"},{"id":"c","text":"dnf module disable nodejs --stream"},{"id":"d","text":"dnf reset module nodejs"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`dnf module reset nodejs` clears the enabled-stream state so you can enable/install a different stream without conflicts. `dnf module clear`, `disable ... --stream`, and `dnf reset module` are not valid forms.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command resets the `nodejs` module so a different stream can be installed cleanly?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command brings the network connection profile `ens3` up using NetworkManager?$rh2$, $rh2$[{"id":"a","text":"nmcli con up ens3"},{"id":"b","text":"nmcli con start ens3"},{"id":"c","text":"ifconfig ens3 up only"},{"id":"d","text":"systemctl start ens3"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`nmcli con up ens3` activates the connection profile. `nmcli con start` is not a valid subcommand, `ifconfig ... up` is deprecated and bypasses NetworkManager, and `ens3` is not a systemd unit.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_and_managing_networking/index","label":"RHEL 9 — Configuring and managing networking"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command brings the network connection profile `ens3` up using NetworkManager?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command lists the available kernel command-line arguments currently applied to the running kernel?$rh2$, $rh2$[{"id":"a","text":"cat /proc/cmdline"},{"id":"b","text":"grubby --running"},{"id":"c","text":"sysctl kernel.cmdline"},{"id":"d","text":"dmesg --cmdline"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`/proc/cmdline` contains the exact arguments the running kernel was booted with. `grubby --running` is not an option, there is no `kernel.cmdline` sysctl, and `dmesg --cmdline` is not valid.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_monitoring_and_updating_the_kernel/index","label":"RHEL 9 — Managing the boot process / rescue & emergency targets"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command lists the available kernel command-line arguments currently applied to the running kernel?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$After `rd.break` and resetting root's password on RHEL 9 with SELinux enforcing, which step ensures the system relabels and boots correctly?$rh2$, $rh2$[{"id":"a","text":"touch /.autorelabel before rebooting"},{"id":"b","text":"Run `setenforce 0` from the initramfs"},{"id":"c","text":"Delete /etc/selinux/config"},{"id":"d","text":"Run `restorecon /etc/shadow` only"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Creating `/.autorelabel` triggers a full SELinux relabel on the next boot so the modified `/etc/shadow` gets the correct context (otherwise login may fail). Disabling SELinux or deleting its config is incorrect, and relabeling only `/etc/shadow` from initramfs is impractical.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_monitoring_and_updating_the_kernel/index","label":"RHEL 9 — Managing the boot process / rescue & emergency targets"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$After `rd.break` and resetting root's password on RHEL 9 with SELinux enforcing, which step ensures the system relabels and boots correctly?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command stops and removes a running rootless container named `web`?$rh2$, $rh2$[{"id":"a","text":"podman stop web ; podman rm web"},{"id":"b","text":"podman delete web"},{"id":"c","text":"podman rm -running web"},{"id":"d","text":"podman kill --remove web"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$Stop the container first (`podman stop web`) then remove it (`podman rm web`); `podman rm -f web` also force-removes a running one. `podman delete`, `rm -running`, and `kill --remove` are not valid commands/options.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/building_running_and_managing_containers/index","label":"RHEL 9 — Building, running, and managing containers"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command stops and removes a running rootless container named `web`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command persists environment variables and a restart policy by generating a systemd unit from an existing container `app`?$rh2$, $rh2$[{"id":"a","text":"podman generate systemd --name app --new --files"},{"id":"b","text":"podman systemd create app"},{"id":"c","text":"systemctl generate app"},{"id":"d","text":"podman export --systemd app"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`podman generate systemd --name app --new --files` writes a unit file (the `--new` form recreates the container on start) suitable for `systemctl --user`. `podman systemd create`, `systemctl generate`, and `podman export --systemd` are not valid.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/building_running_and_managing_containers/index","label":"RHEL 9 — Building, running, and managing containers"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command persists environment variables and a restart policy by generating a systemd unit from an existing container `app`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Deploy, Configure, and Maintain Systems$rh2$, 3, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about DNF modules on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"A module can provide multiple streams representing different versions."},{"id":"b","text":"`dnf module enable name:stream` enables a stream without installing packages."},{"id":"c","text":"Only one stream of a given module can be enabled at a time."},{"id":"d","text":"Modules cannot define installation profiles."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$Modules expose multiple streams (versions), `dnf module enable` selects a stream without installing, and only one stream per module is active at once. Modules DO define profiles (e.g. minimal/default/devel), so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"RHEL 9 — Managing software with the DNF tool"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about DNF modules on RHEL 9.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 2, $rh2$SINGLE$rh2$::"QType", $rh2$Which command displays the UID, primary GID, and group memberships of the user `hugo`?$rh2$, $rh2$[{"id":"a","text":"id hugo"},{"id":"b","text":"who hugo"},{"id":"c","text":"finger -u hugo"},{"id":"d","text":"getent uid hugo"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`id hugo` prints uid, gid, and the list of groups. `who` shows logged-in users, `finger` is not installed by default and the option shown is wrong, and `getent uid` is not a valid database name (use `getent passwd hugo`).$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command displays the UID, primary GID, and group memberships of the user `hugo`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command sets an absolute account-expiration date of 2026-12-31 for user `iris`?$rh2$, $rh2$[{"id":"a","text":"chage -E 2026-12-31 iris"},{"id":"b","text":"usermod -e 2026-12-31"},{"id":"c","text":"passwd -x 2026-12-31 iris"},{"id":"d","text":"chage -d 2026-12-31 iris"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`chage -E 2026-12-31 iris` sets the date the account becomes unusable (`usermod -e <date> iris` is equivalent but the option B form omits the username). `passwd -x` sets max password age, and `chage -d` sets the LAST password-change date.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command sets an absolute account-expiration date of 2026-12-31 for user `iris`?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command removes user `jack` from the supplementary group `developers` without affecting his other groups?$rh2$, $rh2$[{"id":"a","text":"gpasswd -d jack developers"},{"id":"b","text":"usermod -G developers jack"},{"id":"c","text":"groupdel developers"},{"id":"d","text":"usermod -r jack developers"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`gpasswd -d jack developers` removes jack from that one group only. `usermod -G developers jack` would REPLACE all his supplementary groups with just `developers`, `groupdel` deletes the group entirely, and `usermod -r` is not valid here.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command removes user `jack` from the supplementary group `developers` without affecting his other groups?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Users and Groups$rh2$, 4, $rh2$SINGLE$rh2$::"QType", $rh2$You must require ALL users to change their password every 90 days, warn 7 days before, and you want to apply it to the EXISTING user `kate`. Which command does this for kate?$rh2$, $rh2$[{"id":"a","text":"chage -M 90 -W 7 kate"},{"id":"b","text":"chage -d 90 -W 7 kate"},{"id":"c","text":"passwd -n 90 -w 7 kate"},{"id":"d","text":"usermod -M 90 -W 7 kate"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`chage -M 90 -W 7 kate` sets the maximum password age to 90 days and the warning period to 7 days for the existing user. `-d` sets last-change date, `passwd -n` sets MINIMUM age, and `usermod` has no `-M 90 -W 7` aging options.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/managing-users-and-groups_configuring-basic-system-settings","label":"RHEL 9 — Configuring basic system settings: managing users & groups"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$You must require ALL users to change their password every 90 days, warn 7 days before, and you want to apply it to the EXISTING user `kate`. Which command does this for kate?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 2, $rh2$TRUE_FALSE$rh2$::"QType", $rh2$The persistent boot-time SELinux mode is configured via the `SELINUX=` directive in `/etc/selinux/config`.$rh2$, $rh2$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$The `SELINUX=` line in `/etc/selinux/config` (often symlinked from `/etc/sysconfig/selinux`) sets the mode applied at every boot, whereas `setenforce` only changes it at runtime. The statement is true.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$The persistent boot-time SELinux mode is configured via the `SELINUX=` directive in `/etc/selinux/config`.$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command temporarily changes the SELinux context (type) of the file `/web/index.html` to `httpd_sys_content_t` for testing?$rh2$, $rh2$[{"id":"a","text":"chcon -t httpd_sys_content_t /web/index.html"},{"id":"b","text":"semanage fcontext -t httpd_sys_content_t /web/index.html"},{"id":"c","text":"restorecon -t httpd_sys_content_t /web/index.html"},{"id":"d","text":"setsebool httpd_sys_content_t on"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`chcon -t` changes the type label immediately but is NOT persistent across a full relabel (use `semanage fcontext` + `restorecon` for permanence). `restorecon` has no `-t`, and `setsebool` toggles booleans, not file types.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command temporarily changes the SELinux context (type) of the file `/web/index.html` to `httpd_sys_content_t` for testing?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 3, $rh2$SINGLE$rh2$::"QType", $rh2$Which command removes the `http` service from the permanent firewalld configuration of the default zone and applies it?$rh2$, $rh2$[{"id":"a","text":"firewall-cmd --permanent --remove-service=http ; firewall-cmd --reload"},{"id":"b","text":"firewall-cmd --remove-service=http (only)"},{"id":"c","text":"firewall-cmd --permanent --delete=http"},{"id":"d","text":"firewall-cmd --disable http"}]$rh2$::jsonb, $rh2$["a"]$rh2$::jsonb, $rh2$`--permanent --remove-service=http` then `--reload` permanently revokes the rule. Without `--permanent` the change is lost on reload, and `--delete`/`--disable` are not valid firewalld options for services.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/securing_networks/using-and-configuring-firewalld_securing-networks","label":"RHEL 9 — Securing networks: using and configuring firewalld"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Which command removes the `http` service from the permanent firewalld configuration of the default zone and applies it?$rh2$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $rh2$Manage Security$rh2$, 4, $rh2$MULTI$rh2$::"QType", $rh2$Select ALL true statements about SELinux troubleshooting on RHEL 9.$rh2$, $rh2$[{"id":"a","text":"AVC denial messages are recorded by auditd (e.g. in /var/log/audit/audit.log)."},{"id":"b","text":"`ausearch -m avc -ts recent` can surface recent SELinux denials."},{"id":"c","text":"Switching to permissive mode logs denials without blocking access."},{"id":"d","text":"Permissive mode is the recommended permanent fix for SELinux denials."}]$rh2$::jsonb, $rh2$["a","b","c"]$rh2$::jsonb, $rh2$AVC denials go to the audit log, `ausearch -m avc` finds them, and permissive mode logs without enforcing — useful for diagnosis. Leaving SELinux permanently permissive is NOT a recommended fix (correct the contexts/booleans instead), so option D is false.$rh2$, $rh2$[{"url":"https://docs.redhat.com/en/documentation/red_hat_enterprise_linux/9/html/using_selinux/index","label":"RHEL 9 — Using SELinux"}]$rh2$::jsonb, $rh2$PUBLISHED$rh2$::"QStatus", $rh2$manual:rhcsa-seed$rh2$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $rh2$redhat-rhcsa-ex200-p3$rh2$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $rh2$Select ALL true statements about SELinux troubleshooting on RHEL 9.$rh2$);
